  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [formData, setFormData] = useState({
    vencimento: '',
    pagamento: '',
    descricao: '',
    valor: '',
    formaPagamento: 'PIX',
    centroCusto: '',
    subItem: '',
    status: 'PENDENTE' as Status,
    conta: 'GERAL'
  });

  const filtered = transactions.filter(t => {
    const search = searchTerm.toLowerCase();
    return (
      t.descricao.toLowerCase().includes(search) ||
      t.centroCusto.toLowerCase().includes(search) ||
      (t.conta || '').toLowerCase().includes(search)
    );
  });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const transactionData: Transaction = {
      id: editingId || crypto.randomUUID(),
      type: type,
      vencimento: formData.vencimento,
      pagamento: formData.pagamento || undefined,
      descricao: formData.descricao,
      valor: parseFloat(formData.valor),
      formaPagamento: formData.formaPagamento,
      status: formData.status,
      centroCusto: formData.centroCusto || 'OUTROS',
      subItem: formData.subItem || 'DIVERSOS',
      conta: formData.conta
    };

    if (editingId) onUpdate(transactionData);
    else onAdd(transactionData);

    setIsModalOpen(false);
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 overflow-hidden border border-slate-100">
      <div className="p-5 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-4 bg-slate-50/50">
        <h2 className="text-xl font-black text-blue-900 uppercase tracking-tighter">
          {type === 'PAGAR' ? 'Contas a Pagar' : 'Contas a Receber'}
        </h2>
        <div className="flex items-center gap-2">
           <button onClick={() => { setEditingId(null); setIsModalOpen(true); }} className="bg-blue-900 text-white px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 hover:bg-blue-800 transition-all shadow-lg shadow-blue-900/20">
             <i className="fa-solid fa-plus"></i> Novo Registro
           </button>
           <button onClick={() => onDelete(selectedIds)} disabled={selectedIds.length === 0} className={`px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 transition-all ${selectedIds.length > 0 ? 'bg-red-500 text-white shadow-lg shadow-red-500/20' : 'bg-slate-100 text-slate-400 cursor-not-allowed'}`}>
             <i className="fa-solid fa-trash-can"></i> {selectedIds.length > 0 ? `Excluir (${selectedIds.length})` : 'Excluir'}
           </button>
        </div>
      </div>

      <div className="p-4 bg-white border-b border-slate-50">
        <div className="relative group">
          <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-900 transition-colors"></i>
          <input 
            type="text" 
            placeholder="Pesquisar por descrição, conta, categoria..." 
            className="w-full pl-12 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-4 focus:ring-blue-900/5 focus:border-blue-900 outline-none text-sm transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest">
              <th className="p-5 w-12 text-center">
                <input type="checkbox" onChange={(e) => e.target.checked ? setSelectedIds(filtered.map(t => t.id)) : setSelectedIds([])} />
              </th>
              <th className="p-5">Data</th>
              <th className="p-5">Descrição / Conta</th>
              <th className="p-5 text-right">Valor</th>
              <th className="p-5">Categoria</th>
              <th className="p-5">Status</th>
              <th className="p-5 text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="text-sm divide-y divide-slate-100">
            {filtered.map((t) => (
              <tr key={t.id} className={`${selectedIds.includes(t.id) ? 'bg-blue-50/50' : 'hover:bg-slate-50/30'} transition-colors group`}>
                <td className="p-5 text-center">
                   <input type="checkbox" checked={selectedIds.includes(t.id)} onChange={() => setSelectedIds(prev => prev.includes(t.id) ? prev.filter(i => i !== t.id) : [...prev, t.id])} />
                </td>
                <td className="p-5 font-bold text-slate-600">{new Date(t.vencimento).toLocaleDateString('pt-BR')}</td>
                <td className="p-5">
                  <div className="font-black text-blue-900 uppercase tracking-tight leading-none mb-1">{t.descricao}</div>
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] bg-slate-100 px-2 py-0.5 rounded font-black text-slate-500 uppercase">{t.conta || 'GERAL'}</span>
                    <span className="text-[9px] text-slate-400 uppercase font-bold">{t.formaPagamento}</span>
                  </div>
                </td>
                <td className={`p-5 text-right font-black text-lg ${type === 'PAGAR' ? 'text-red-500' : 'text-emerald-600'}`}>
                   R$ {t.valor.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                </td>
                <td className="p-5">
                  <div className="text-[10px] uppercase font-black text-slate-400 leading-none">{t.centroCusto}</div>
                  <div className="text-[9px] font-bold text-slate-300 uppercase">{t.subItem}</div>
                </td>
                <td className="p-5">
                  <span className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest ${
                    t.status === 'PENDENTE' ? 'bg-amber-100 text-amber-700' : 'bg-emerald-100 text-emerald-700'
                  }`}>
                    {t.status}
                  </span>
                </td>
                <td className="p-5 text-center">
                  <button onClick={() => {
                    setEditingId(t.id);
                    setFormData({
                      vencimento: t.vencimento, pagamento: t.pagamento || '', descricao: t.descricao,
                      valor: t.valor.toString(), formaPagamento: t.formaPagamento, centroCusto: t.centroCusto,
                      subItem: t.subItem, status: t.status, conta: t.conta || 'GERAL'
                    });
                    setIsModalOpen(true);
                  }} className="text-blue-900 hover:bg-blue-50 p-3 rounded-xl transition-all"><i className="fa-solid fa-pen-to-square"></i></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-blue-900/20 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xl overflow-hidden animate-in fade-in zoom-in duration-300 border border-white/20">
            <div className="bg-blue-900 p-8 flex justify-between items-center text-white">
              <h3 className="text-xl font-black uppercase tracking-tighter">Lançamento Financeiro</h3>
              <button onClick={() => setIsModalOpen(false)} className="bg-white/10 w-10 h-10 rounded-full flex items-center justify-center hover:bg-white/20 transition-all">&times;</button>
            </div>
            <form onSubmit={handleSave} className="p-8 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Vencimento</label>
                  <input type="date" className="w-full p-3 border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 transition-all" value={formData.vencimento} onChange={e => setFormData({...formData, vencimento: e.target.value})} required />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Conta</label>
                  <select className="w-full p-3 border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 transition-all" value={formData.conta} onChange={e => setFormData({...formData, conta: e.target.value})}>
                    <option value="SANTANDER">SANTANDER</option>
                    <option value="NUBANK">NUBANK</option>
                    <option value="CAIXA">CAIXA</option>
                    <option value="INTER">INTER</option>
                    <option value="BRADESCO">BRADESCO</option>
                    <option value="GERAL">GERAL / DINHEIRO</option>
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Descrição</label>
                <input type="text" className="w-full p-3 border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 uppercase" placeholder="EX: PAGAMENTO ENERGIA" value={formData.descricao} onChange={e => setFormData({...formData, descricao: e.target.value.toUpperCase()})} required />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                   <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Valor (R$)</label>
                   <input type="number" step="0.01" className="w-full p-3 border border-slate-200 rounded-xl outline-none font-bold" value={formData.valor} onChange={e => setFormData({...formData, valor: e.target.value})} required />
                </div>
                <div>
                   <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Forma</label>
                   <select className="w-full p-3 border border-slate-200 rounded-xl outline-none" value={formData.formaPagamento} onChange={e => setFormData({...formData, formaPagamento: e.target.value})}>
                     <option>PIX</option><option>BOLETO</option><option>TRANSFERÊNCIA</option><option>DINHEIRO</option><option>CARTÃO</option>
                   </select>
                </div>
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 px-4 py-4 bg-slate-100 rounded-2xl font-black text-slate-500 hover:bg-slate-200 transition-all uppercase text-[10px] tracking-widest">Cancelar</button>
                <button type="submit" className="flex-1 px-4 py-4 bg-blue-900 text-white rounded-2xl font-black hover:bg-blue-800 shadow-xl shadow-blue-900/20 transition-all uppercase text-[10px] tracking-widest">Confirmar Saldo</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default TransactionTable;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Tab, Transaction, CostCenter } from './types';
import Login from './components/Login';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionTable from './components/TransactionTable';
import CostCentersView from './components/CostCentersView';
import CashFlow from './components/CashFlow';
import Details from './components/Details';
import CredentialsManager from './components/CredentialsManager';
import { supabase } from './lib/supabase';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<Tab | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [appUsers, setAppUsers] = useState<User[]>([]);
  const [costCenters, setCostCenters] = useState<CostCenter[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [errorType, setErrorType] = useState<'SCHEMA_HIDDEN' | 'TABLES_MISSING' | null>(null);
  const [activeAccount, setActiveAccount] = useState<string>('TODAS');

  const fetchData = async () => {
    setIsLoading(true);
    setErrorType(null);
    try {
      // Teste de conexão básico
      const { data: usersData, error: uErr, status } = await supabase.from('users').select('*');

      if (uErr) {
        console.error("Erro Supabase:", uErr);
        // PGRST106 significa que o esquema 'public' não está exposto nas configurações da API
        if (uErr.code === 'PGRST106' || uErr.message.includes('Invalid schema')) {
          setErrorType('SCHEMA_HIDDEN');
          setIsLoading(false);
          return;
        }
        // 42P01 significa que a tabela não existe
        if (uErr.code === '42P01' || status === 406) {
          setErrorType('TABLES_MISSING');
          setIsLoading(false);
          return;
        }
      }

      const [transactionsRes, costCentersRes] = await Promise.all([
        supabase.from('transactions').select('*').order('vencimento', { ascending: false }),
        supabase.from('cost_centers').select('*').order('nome')
      ]);

      let currentUsers = usersData || [];
      const hasAdmin = currentUsers.some(u => u.login === 'admin');

      if (!hasAdmin && !uErr) {
        const adminUser: User = {
          login: 'admin',
          senha: '123',
          email: 'admin@multiplan.com',
          permissions: {
            centroCusto: true, contasPagar: true, contasReceber: true,
            dashboard: true, fluxoCaixa: true, detalhes: true, planCredencias: true
          }
        };
        await supabase.from('users').insert(adminUser);
        currentUsers = [...currentUsers, adminUser];
      }

      setAppUsers(currentUsers);
      if (transactionsRes.data) setTransactions(transactionsRes.data);
      if (costCentersRes.data) {
        setCostCenters(costCentersRes.data.map(cc => ({
          id: cc.id, nome: cc.nome, tipo: cc.tipo, subItens: cc.sub_itens || []
        })));
      }
    } catch (error) {
      console.error('Erro crítico:', error);
      setErrorType('TABLES_MISSING');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const accounts = useMemo(() => {
    const unique = Array.from(new Set(transactions.map(t => t.conta || 'GERAL')));
    return ['TODAS', ...unique.sort()];
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    if (activeAccount === 'TODAS') return transactions;
    return transactions.filter(t => (t.conta || 'GERAL') === activeAccount);
  }, [transactions, activeAccount]);

  const handleLogin = (login: string, pass: string) => {
    const foundUser = appUsers.find(u => u.login === login && u.senha === pass);
    if (foundUser) {
      setUser(foundUser);
      if (foundUser.permissions.dashboard) setActiveTab(Tab.DASHBOARD);
      else setActiveTab(Tab.CONTAS_PAGAR);
    } else {
      alert('Login ou senha inválidos!');
    }
  };

  const handleRegister = async (login: string, email: string, pass: string) => {
    const newUser: User = {
      login, senha: pass, email,
      permissions: { centroCusto: false, contasPagar: true, contasReceber: true, dashboard: true, fluxoCaixa: false, detalhes: false, planCredencias: false }
    };
    const { error } = await supabase.from('users').insert(newUser);
    if (error) {
      alert('Erro no cadastro. Verifique as configurações do banco.');
      return false;
    }
    await fetchData();
    alert('Conta criada!');
    return true;
  };

  if (errorType === 'SCHEMA_HIDDEN') {
    return (
      <div className="min-h-screen bg-slate-900 text-white p-8 flex flex-col items-center justify-center font-sans">
        <div className="max-w-2xl w-full space-y-8 animate-in fade-in zoom-in duration-500">
          <div className="text-center space-y-4">
            <i className="fa-solid fa-lock-open text-6xl text-orange-500 mb-4 animate-bounce"></i>
            <h1 className="text-3xl font-black uppercase tracking-tighter">Esquema Bloqueado (PGRST106)</h1>
            <div className="bg-orange-500/10 border border-orange-500/20 p-4 rounded-xl text-orange-200 text-sm">
              Sua API do Supabase não está configurada para mostrar o esquema <strong>public</strong>.
            </div>
          </div>

          <div className="bg-slate-800 p-8 rounded-2xl border border-slate-700 space-y-6 shadow-2xl">
            <h2 className="text-xl font-bold flex items-center gap-3">
              <span className="bg-blue-600 w-8 h-8 rounded-full flex items-center justify-center text-xs">1</span>
              Como resolver no Painel Supabase:
            </h2>
            <ol className="space-y-4 text-slate-300 text-sm list-decimal list-inside">
              <li>No menu lateral, clique em <i className="fa-solid fa-cog mx-1 text-blue-400"></i> <strong>Settings</strong>.</li>
              <li>Clique na aba <i className="fa-solid fa-link mx-1 text-blue-400"></i> <strong>API</strong>.</li>
              <li>Desça até a seção <strong>Data API</strong>.</li>
              <li>No campo <strong>Exposed schemas</strong>, adicione <strong>"public"</strong>.</li>
              <li>Clique em <strong>Save</strong> (topo ou rodapé da página).</li>
            </ol>
            <p className="text-xs text-slate-500 italic">Após salvar, aguarde 10 segundos e clique no botão abaixo.</p>
          </div>

          <button onClick={fetchData} className="w-full bg-blue-600 hover:bg-blue-500 text-white font-black py-4 rounded-xl uppercase tracking-widest transition-all shadow-xl flex items-center justify-center gap-3">
            <i className="fa-solid fa-sync"></i> Configuração Concluída. Recarregar!
          </button>
        </div>
      </div>
    );
  }

  if (errorType === 'TABLES_MISSING') {
    return (
      <div className="min-h-screen bg-slate-900 text-white p-8 flex flex-col items-center justify-center font-sans">
        <div className="max-w-3xl w-full space-y-8 animate-in fade-in zoom-in duration-500">
          <div className="text-center space-y-4">
            <i className="fa-solid fa-database text-6xl text-blue-500 mb-4"></i>
            <h1 className="text-3xl font-black uppercase tracking-tighter">Tabelas não encontradas</h1>
            <p className="text-slate-400">Execute o script abaixo no SQL Editor do Supabase para criar a estrutura:</p>
          </div>

          <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 space-y-4 shadow-2xl">
            <pre className="bg-black/50 p-4 rounded-lg text-[11px] text-green-400 overflow-x-auto border border-white/5 max-h-64 leading-relaxed font-mono">
{`CREATE TABLE IF NOT EXISTS users (login TEXT PRIMARY KEY, senha TEXT NOT NULL, email TEXT, permissions JSONB NOT NULL);
CREATE TABLE IF NOT EXISTS cost_centers (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), nome TEXT NOT NULL, tipo TEXT NOT NULL, sub_itens TEXT[] DEFAULT '{}');
CREATE TABLE IF NOT EXISTS transactions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), type TEXT NOT NULL, vencimento DATE NOT NULL, pagamento DATE, descricao TEXT NOT NULL, valor NUMERIC(15,2) NOT NULL, "formaPagamento" TEXT NOT NULL, status TEXT NOT NULL, "centroCusto" TEXT NOT NULL, "subItem" TEXT NOT NULL, cliente TEXT, conta TEXT DEFAULT 'GERAL');

ALTER TABLE users DISABLE ROW LEVEL SECURITY;
ALTER TABLE cost_centers DISABLE ROW LEVEL SECURITY;
ALTER TABLE transactions DISABLE ROW LEVEL SECURITY;`}
            </pre>
          </div>

          <button onClick={fetchData} className="w-full bg-blue-600 hover:bg-blue-500 text-white font-black py-4 rounded-xl uppercase tracking-widest transition-all shadow-xl flex items-center justify-center gap-3">
            <i className="fa-solid fa-sync"></i> Tentar novamente
          </button>
        </div>
      </div>
    );
  }

  if (isLoading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-white text-blue-900 gap-4">
      <i className="fa-solid fa-circle-notch fa-spin text-4xl"></i>
      <span className="text-[10px] font-black uppercase tracking-[0.2em] opacity-50">Sincronizando Multiplan...</span>
    </div>
  );

  if (!user) return <Login onLogin={handleLogin} onRegister={handleRegister} />;

  return (
    <Layout user={user} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={() => setUser(null)}>
      <div className="mb-6">
        <div className="flex items-center gap-4 mb-3">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <i className="fa-solid fa-building-columns"></i> Filtro por Conta
          </h3>
          <div className="h-px bg-slate-200 flex-1"></div>
        </div>
        <div className="flex items-center gap-2 overflow-x-auto pb-2 scrollbar-hide">
          {accounts.map(acc => (
            <button
              key={acc}
              onClick={() => setActiveAccount(acc)}
              className={`px-5 py-2 rounded-xl text-xs font-bold transition-all whitespace-nowrap border-2 ${
                activeAccount === acc 
                ? 'bg-blue-900 text-white border-blue-900 shadow-lg shadow-blue-900/20' 
                : 'bg-white text-slate-500 border-slate-100 hover:border-blue-200 hover:text-blue-900 shadow-sm'
              }`}
            >
              {acc}
            </button>
          ))}
        </div>
      </div>

      <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
        {activeTab === Tab.DASHBOARD && <Dashboard transactions={filteredTransactions} />}
        {activeTab === Tab.CONTAS_PAGAR && (
          <TransactionTable 
            type="PAGAR" 
            transactions={filteredTransactions.filter(t => t.type === 'PAGAR')} 
            onAdd={async t => { await supabase.from('transactions').insert(t); fetchData(); }} 
            onUpdate={async t => { await supabase.from('transactions').update(t).eq('id', t.id); fetchData(); }} 
            onDelete={async ids => { await supabase.from('transactions').delete().in('id', ids); fetchData(); }} 
          />
        )}
        {activeTab === Tab.CONTAS_RECEBER && (
          <TransactionTable 
            type="RECEBER" 
            transactions={filteredTransactions.filter(t => t.type === 'RECEBER')} 
            onAdd={async t => { await supabase.from('transactions').insert(t); fetchData(); }} 
            onUpdate={async t => { await supabase.from('transactions').update(t).eq('id', t.id); fetchData(); }} 
            onDelete={async ids => { await supabase.from('transactions').delete().in('id', ids); fetchData(); }} 
          />
        )}
        {activeTab === Tab.CENTRO_CUSTO && <CostCentersView costCenters={costCenters} onSave={async cc => { await supabase.from('cost_centers').upsert({id: cc.id, nome: cc.nome, tipo: cc.tipo, sub_itens: cc.subItens}); fetchData(); }} onDelete={async id => { await supabase.from('cost_centers').delete().eq('id', id); fetchData(); }} />}
        {activeTab === Tab.FLUXO_CAIXA && <CashFlow transactions={filteredTransactions} />}
        {activeTab === Tab.DETALHES && <Details transactions={filteredTransactions} />}
        {activeTab === Tab.PLAN_CREDENCIAS && <CredentialsManager users={appUsers} onUpdateUsers={async nu => { for(const u of nu) { await supabase.from('users').upsert(u); } fetchData(); }} />}
      </div>
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Transaction, TransactionType, Status } from '../types';
import { COST_CENTERS } from '../constants';

interface TransactionTableProps {
  type: TransactionType;
  transactions: Transaction[];
  onAdd: (transaction: Transaction) => void;
  onUpdate: (transaction: Transaction) => void;
  onDelete: (ids: string[]) => void;
}

const TransactionTable: React.FC<TransactionTableProps> = ({ type, transactions, onAdd, onUpdate, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [formData, setFormData] = useState({
    vencimento: new Date().toISOString().split('T')[0],
    pagamento: '',
    descricao: '',
    valor: '',
    formaPagamento: 'PIX',
    centroCusto: '',
    subItem: '',
    status: 'PENDENTE' as Status,
    conta: 'GERAL'
  });

  // Filtrar centros de custo pelo tipo (Receita ou Despesa)
  const availableCostCenters = COST_CENTERS.filter(cc => cc.tipo === (type === 'RECEBER' ? 'RECEITA' : 'DESPESA'));

  // Obter sub-itens do centro de custo selecionado
  const availableSubItems = availableCostCenters.find(cc => cc.nome === formData.centroCusto)?.subItens || [];

  const filtered = transactions.filter(t => {
    const search = searchTerm.toLowerCase();
    return (
      t.descricao.toLowerCase().includes(search) ||
      t.centroCusto.toLowerCase().includes(search) ||
      (t.conta || '').toLowerCase().includes(search)
    );
  });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const transactionData: Transaction = {
      id: editingId || crypto.randomUUID(),
      type: type,
      vencimento: formData.vencimento,
      pagamento: formData.status !== 'PENDENTE' ? (formData.pagamento || formData.vencimento) : undefined,
      descricao: formData.descricao,
      valor: parseFloat(formData.valor),
      formaPagamento: formData.formaPagamento,
      status: formData.status,
      centroCusto: formData.centroCusto,
      subItem: formData.subItem,
      conta: formData.conta
    };

    if (editingId) onUpdate(transactionData);
    else onAdd(transactionData);

    setIsModalOpen(false);
    resetForm();
  };

  const resetForm = () => {
    setFormData({
      vencimento: new Date().toISOString().split('T')[0],
      pagamento: '',
      descricao: '',
      valor: '',
      formaPagamento: 'PIX',
      centroCusto: '',
      subItem: '',
      status: 'PENDENTE',
      conta: 'GERAL'
    });
    setEditingId(null);
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 overflow-hidden border border-slate-100">
      <div className="p-5 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-4 bg-slate-50/50">
        <h2 className="text-xl font-black text-blue-900 uppercase tracking-tighter">
          {type === 'PAGAR' ? 'Contas a Pagar' : 'Contas a Receber'}
        </h2>
        <div className="flex items-center gap-2">
           <button onClick={() => { resetForm(); setIsModalOpen(true); }} className="bg-blue-900 text-white px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 hover:bg-blue-800 transition-all shadow-lg shadow-blue-900/20">
             <i className="fa-solid fa-plus"></i> Novo Registro
           </button>
           <button onClick={() => onDelete(selectedIds)} disabled={selectedIds.length === 0} className={`px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 transition-all ${selectedIds.length > 0 ? 'bg-red-500 text-white shadow-lg shadow-red-500/20' : 'bg-slate-100 text-slate-400 cursor-not-allowed'}`}>
             <i className="fa-solid fa-trash-can"></i> {selectedIds.length > 0 ? `Excluir (${selectedIds.length})` : 'Excluir'}
           </button>
        </div>
      </div>

      <div className="p-4 bg-white border-b border-slate-50">
        <div className="relative group">
          <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-900 transition-colors"></i>
          <input 
            type="text" 
            placeholder="Pesquisar por descrição, conta, categoria..." 
            className="w-full pl-12 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-4 focus:ring-blue-900/5 focus:border-blue-900 outline-none text-sm transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest">
              <th className="p-5 w-12 text-center">
                <input type="checkbox" onChange={(e) => e.target.checked ? setSelectedIds(filtered.map(t => t.id)) : setSelectedIds([])} />
              </th>
              <th className="p-5">Data</th>
              <th className="p-5">Descrição / Conta</th>
              <th className="p-5 text-right">Valor</th>
              <th className="p-5">Categoria</th>
              <th className="p-5">Status</th>
              <th className="p-5 text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="text-sm divide-y divide-slate-100">
            {filtered.map((t) => (
              <tr key={t.id} className={`${selectedIds.includes(t.id) ? 'bg-blue-50/50' : 'hover:bg-slate-50/30'} transition-colors group`}>
                <td className="p-5 text-center">
                   <input type="checkbox" checked={selectedIds.includes(t.id)} onChange={() => setSelectedIds(prev => prev.includes(t.id) ? prev.filter(i => i !== t.id) : [...prev, t.id])} />
                </td>
                <td className="p-5 font-bold text-slate-600">{new Date(t.vencimento).toLocaleDateString('pt-BR')}</td>
                <td className="p-5">
                  <div className="font-black text-blue-900 uppercase tracking-tight leading-none mb-1">{t.descricao}</div>
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] bg-slate-100 px-2 py-0.5 rounded font-black text-slate-500 uppercase">{t.conta || 'GERAL'}</span>
                    <span className="text-[9px] text-slate-400 uppercase font-bold">{t.formaPagamento}</span>
                  </div>
                </td>
                <td className={`p-5 text-right font-black text-lg ${type === 'PAGAR' ? 'text-red-500' : 'text-emerald-600'}`}>
                   R$ {t.valor.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                </td>
                <td className="p-5">
                  <div className="text-[10px] uppercase font-black text-slate-400 leading-none">{t.centroCusto}</div>
                  <div className="text-[9px] font-bold text-slate-300 uppercase">{t.subItem}</div>
                </td>
                <td className="p-5">
                  <span className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest ${
                    t.status === 'PENDENTE' ? 'bg-amber-100 text-amber-700' : 'bg-emerald-100 text-emerald-700'
                  }`}>
                    {t.status}
                  </span>
                </td>
                <td className="p-5 text-center">
                  <button onClick={() => {
                    setEditingId(t.id);
                    setFormData({
                      vencimento: t.vencimento, pagamento: t.pagamento || '', descricao: t.descricao,
                      valor: t.valor.toString(), formaPagamento: t.formaPagamento, centroCusto: t.centroCusto,
                      subItem: t.subItem, status: t.status, conta: t.conta || 'GERAL'
                    });
                    setIsModalOpen(true);
                  }} className="text-blue-900 hover:bg-blue-50 p-3 rounded-xl transition-all"><i className="fa-solid fa-pen-to-square"></i></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-blue-900/40 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl overflow-hidden animate-in fade-in zoom-in duration-300 border border-white/20">
            <div className="bg-blue-900 p-6 flex justify-between items-center text-white">
              <div>
                <h3 className="text-xl font-black uppercase tracking-tighter">
                  {editingId ? 'Editar Lançamento' : 'Novo Lançamento'}
                </h3>
                <p className="text-[10px] font-bold text-white/50 uppercase tracking-widest">{type === 'PAGAR' ? 'Contas a Pagar' : 'Contas a Receber'}</p>
              </div>
              <button onClick={() => setIsModalOpen(false)} className="bg-white/10 w-10 h-10 rounded-full flex items-center justify-center hover:bg-white/20 transition-all font-bold text-xl">&times;</button>
            </div>

            <form onSubmit={handleSave} className="p-6 space-y-5 overflow-y-auto max-h-[80vh]">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Data Vencimento</label>
                  <input type="date" className="w-full p-3 border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 transition-all" value={formData.vencimento} onChange={e => setFormData({...formData, vencimento: e.target.value})} required />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Conta / Banco</label>
                  <select className="w-full p-3 border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 transition-all font-bold" value={formData.conta} onChange={e => setFormData({...formData, conta: e.target.value})}>
                    <option value="SANTANDER">SANTANDER</option>
                    <option value="NUBANK">NUBANK</option>
                    <option value="CAIXA">CAIXA</option>
                    <option value="INTER">INTER</option>
                    <option value="BRADESCO">BRADESCO</option>
                    <option value="GERAL">GERAL / DINHEIRO</option>
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Descrição do Lançamento</label>
                <input type="text" className="w-full p-3 border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 uppercase font-medium" placeholder="Ex: PAGAMENTO FORNECEDOR X" value={formData.descricao} onChange={e => setFormData({...formData, descricao: e.target.value.toUpperCase()})} required />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                   <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Valor (R$)</label>
                   <input type="number" step="0.01" className="w-full p-3 border border-slate-200 rounded-xl outline-none font-black text-lg text-blue-900" placeholder="0,00" value={formData.valor} onChange={e => setFormData({...formData, valor: e.target.value})} required />
                </div>
                <div>
                   <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Status do Pagamento</label>
                   <select className={`w-full p-3 border rounded-xl outline-none font-black text-xs ${formData.status === 'PENDENTE' ? 'border-amber-200 bg-amber-50 text-amber-700' : 'border-emerald-200 bg-emerald-50 text-emerald-700'}`} value={formData.status} onChange={e => setFormData({...formData, status: e.target.value as Status})}>
                     <option value="PENDENTE">🟡 PENDENTE</option>
                     {type === 'PAGAR' ? <option value="PAGO">🟢 PAGO</option> : <option value="RECEBIDO">🟢 RECEBIDO</option>}
                   </select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                   <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Centro de Custo</label>
                   <select className="w-full p-3 border border-slate-200 rounded-xl outline-none text-sm" value={formData.centroCusto} onChange={e => setFormData({...formData, centroCusto: e.target.value, subItem: ''})} required>
                     <option value="">Selecione...</option>
                     {availableCostCenters.map(cc => <option key={cc.id} value={cc.nome}>{cc.nome}</option>)}
                   </select>
                </div>
                <div>
                   <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Sub-item</label>
                   <select className="w-full p-3 border border-slate-200 rounded-xl outline-none text-sm" value={formData.subItem} onChange={e => setFormData({...formData, subItem: e.target.value})} required disabled={!formData.centroCusto}>
                     <option value="">Selecione...</option>
                     {availableSubItems.map(si => <option key={si} value={si}>{si}</option>)}
                   </select>
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Forma de Movimentação</label>
                <div className="grid grid-cols-3 gap-2">
                  {['PIX', 'BOLETO', 'DINHEIRO', 'CARTÃO', 'TRANSFERÊNCIA'].map(forma => (
                    <button type="button" key={forma} onClick={() => setFormData({...formData, formaPagamento: forma})} className={`py-2.5 rounded-xl text-[10px] font-black transition-all border ${formData.formaPagamento === forma ? 'bg-blue-900 text-white border-blue-900 shadow-lg shadow-blue-900/20' : 'bg-slate-50 text-slate-400 border-slate-100 hover:border-slate-300'}`}>
                      {forma}
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 px-4 py-4 bg-slate-100 rounded-2xl font-black text-slate-500 hover:bg-slate-200 transition-all uppercase text-[10px] tracking-widest">Cancelar</button>
                <button type="submit" className="flex-1 px-4 py-4 bg-blue-900 text-white rounded-2xl font-black hover:bg-blue-800 shadow-xl shadow-blue-900/30 transition-all uppercase text-[10px] tracking-widest flex items-center justify-center gap-2">
                  <i className="fa-solid fa-check"></i> Finalizar Lançamento
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default TransactionTable;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Tab, Transaction, CostCenter } from './types';
import Login from './components/Login';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionTable from './components/TransactionTable';
import CostCentersView from './components/CostCentersView';
import CashFlow from './components/CashFlow';
import Details from './components/Details';
import CredentialsManager from './components/CredentialsManager';
import { supabase } from './lib/supabase';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<Tab | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [appUsers, setAppUsers] = useState<User[]>([]);
  const [costCenters, setCostCenters] = useState<CostCenter[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [errorType, setErrorType] = useState<'SCHEMA_HIDDEN' | 'TABLES_MISSING' | null>(null);
  const [activeAccount, setActiveAccount] = useState<string>('TODAS');

  const fetchData = async () => {
    setIsLoading(true);
    setErrorType(null);
    try {
      // Teste de conexão básico
      const { data: usersData, error: uErr, status } = await supabase.from('users').select('*');

      if (uErr) {
        console.error("Erro Supabase:", uErr);
        // PGRST106 significa que o esquema 'public' não está exposto nas configurações da API
        if (uErr.code === 'PGRST106' || uErr.message.includes('Invalid schema')) {
          setErrorType('SCHEMA_HIDDEN');
          setIsLoading(false);
          return;
        }
        // 42P01 significa que a tabela não existe
        if (uErr.code === '42P01' || status === 406) {
          setErrorType('TABLES_MISSING');
          setIsLoading(false);
          return;
        }
      }

      const [transactionsRes, costCentersRes] = await Promise.all([
        supabase.from('transactions').select('*').order('vencimento', { ascending: false }),
        supabase.from('cost_centers').select('*').order('nome')
      ]);

      let currentUsers = usersData || [];
      const hasAdmin = currentUsers.some(u => u.login === 'admin');

      if (!hasAdmin && !uErr) {
        const adminUser: User = {
          login: 'admin',
          senha: '123',
          email: 'admin@multiplan.com',
          permissions: {
            centroCusto: true, contasPagar: true, contasReceber: true,
            dashboard: true, fluxoCaixa: true, detalhes: true, planCredencias: true
          }
        };
        await supabase.from('users').insert(adminUser);
        currentUsers = [...currentUsers, adminUser];
      }

      setAppUsers(currentUsers);
      if (transactionsRes.data) setTransactions(transactionsRes.data);
      if (costCentersRes.data) {
        setCostCenters(costCentersRes.data.map(cc => ({
          id: cc.id, nome: cc.nome, tipo: cc.tipo, subItens: cc.sub_itens || []
        })));
      }
    } catch (error) {
      console.error('Erro crítico:', error);
      setErrorType('TABLES_MISSING');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const accounts = useMemo(() => {
    const unique = Array.from(new Set(transactions.map(t => t.conta || 'GERAL')));
    return ['TODAS', ...unique.sort()];
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    if (activeAccount === 'TODAS') return transactions;
    return transactions.filter(t => (t.conta || 'GERAL') === activeAccount);
  }, [transactions, activeAccount]);

  const handleLogin = (login: string, pass: string) => {
    const foundUser = appUsers.find(u => u.login === login && u.senha === pass);
    if (foundUser) {
      setUser(foundUser);
      if (foundUser.permissions.dashboard) setActiveTab(Tab.DASHBOARD);
      else setActiveTab(Tab.CONTAS_PAGAR);
    } else {
      alert('Login ou senha inválidos!');
    }
  };

  const handleRegister = async (login: string, email: string, pass: string) => {
    const newUser: User = {
      login, senha: pass, email,
      permissions: { centroCusto: false, contasPagar: true, contasReceber: true, dashboard: true, fluxoCaixa: false, detalhes: false, planCredencias: false }
    };
    const { error } = await supabase.from('users').insert(newUser);
    if (error) {
      alert('Erro no cadastro. Verifique as configurações do banco.');
      return false;
    }
    await fetchData();
    alert('Conta criada!');
    return true;
  };

  if (errorType === 'SCHEMA_HIDDEN') {
    return (
      <div className="min-h-screen bg-slate-900 text-white p-8 flex flex-col items-center justify-center font-sans">
        <div className="max-w-2xl w-full space-y-8 animate-in fade-in zoom-in duration-500">
          <div className="text-center space-y-4">
            <i className="fa-solid fa-lock-open text-6xl text-orange-500 mb-4 animate-bounce"></i>
            <h1 className="text-3xl font-black uppercase tracking-tighter">Esquema Bloqueado (PGRST106)</h1>
            <div className="bg-orange-500/10 border border-orange-500/20 p-4 rounded-xl text-orange-200 text-sm">
              Sua API do Supabase não está configurada para mostrar o esquema <strong>public</strong>.
            </div>
          </div>

          <div className="bg-slate-800 p-8 rounded-2xl border border-slate-700 space-y-6 shadow-2xl">
            <h2 className="text-xl font-bold flex items-center gap-3">
              <span className="bg-blue-600 w-8 h-8 rounded-full flex items-center justify-center text-xs">1</span>
              Como resolver no Painel Supabase:
            </h2>
            <ol className="space-y-4 text-slate-300 text-sm list-decimal list-inside">
              <li>No menu lateral, clique em <i className="fa-solid fa-cog mx-1 text-blue-400"></i> <strong>Settings</strong>.</li>
              <li>Clique na aba <i className="fa-solid fa-link mx-1 text-blue-400"></i> <strong>API</strong>.</li>
              <li>Desça até a seção <strong>Data API</strong>.</li>
              <li>No campo <strong>Exposed schemas</strong>, adicione <strong>"public"</strong>.</li>
              <li>Clique em <strong>Save</strong> (topo ou rodapé da página).</li>
            </ol>
            <p className="text-xs text-slate-500 italic">Após salvar, aguarde 10 segundos e clique no botão abaixo.</p>
          </div>

          <button onClick={fetchData} className="w-full bg-blue-600 hover:bg-blue-500 text-white font-black py-4 rounded-xl uppercase tracking-widest transition-all shadow-xl flex items-center justify-center gap-3">
            <i className="fa-solid fa-sync"></i> Configuração Concluída. Recarregar!
          </button>
        </div>
      </div>
    );
  }

  if (errorType === 'TABLES_MISSING') {
    return (
      <div className="min-h-screen bg-slate-900 text-white p-8 flex flex-col items-center justify-center font-sans">
        <div className="max-w-3xl w-full space-y-8 animate-in fade-in zoom-in duration-500">
          <div className="text-center space-y-4">
            <i className="fa-solid fa-database text-6xl text-blue-500 mb-4"></i>
            <h1 className="text-3xl font-black uppercase tracking-tighter">Tabelas não encontradas</h1>
            <p className="text-slate-400">Execute o script abaixo no SQL Editor do Supabase para criar a estrutura:</p>
          </div>

          <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 space-y-4 shadow-2xl">
            <pre className="bg-black/50 p-4 rounded-lg text-[11px] text-green-400 overflow-x-auto border border-white/5 max-h-64 leading-relaxed font-mono">
{`CREATE TABLE IF NOT EXISTS users (login TEXT PRIMARY KEY, senha TEXT NOT NULL, email TEXT, permissions JSONB NOT NULL);
CREATE TABLE IF NOT EXISTS cost_centers (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), nome TEXT NOT NULL, tipo TEXT NOT NULL, sub_itens TEXT[] DEFAULT '{}');
CREATE TABLE IF NOT EXISTS transactions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), type TEXT NOT NULL, vencimento DATE NOT NULL, pagamento DATE, descricao TEXT NOT NULL, valor NUMERIC(15,2) NOT NULL, "formaPagamento" TEXT NOT NULL, status TEXT NOT NULL, "centroCusto" TEXT NOT NULL, "subItem" TEXT NOT NULL, cliente TEXT, conta TEXT DEFAULT 'GERAL');

ALTER TABLE users DISABLE ROW LEVEL SECURITY;
ALTER TABLE cost_centers DISABLE ROW LEVEL SECURITY;
ALTER TABLE transactions DISABLE ROW LEVEL SECURITY;`}
            </pre>
          </div>

          <button onClick={fetchData} className="w-full bg-blue-600 hover:bg-blue-500 text-white font-black py-4 rounded-xl uppercase tracking-widest transition-all shadow-xl flex items-center justify-center gap-3">
            <i className="fa-solid fa-sync"></i> Tentar novamente
          </button>
        </div>
      </div>
    );
  }

  if (isLoading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-white text-blue-900 gap-4">
      <i className="fa-solid fa-circle-notch fa-spin text-4xl"></i>
      <span className="text-[10px] font-black uppercase tracking-[0.2em] opacity-50">Sincronizando Multiplan...</span>
    </div>
  );

  if (!user) return <Login onLogin={handleLogin} onRegister={handleRegister} />;

  return (
    <Layout user={user} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={() => setUser(null)}>
      <div className="mb-6">
        <div className="flex items-center gap-4 mb-3">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <i className="fa-solid fa-building-columns"></i> Filtro por Conta
          </h3>
          <div className="h-px bg-slate-200 flex-1"></div>
        </div>
        <div className="flex items-center gap-2 overflow-x-auto pb-2 scrollbar-hide">
          {accounts.map(acc => (
            <button
              key={acc}
              onClick={() => setActiveAccount(acc)}
              className={`px-5 py-2 rounded-xl text-xs font-bold transition-all whitespace-nowrap border-2 ${
                activeAccount === acc 
                ? 'bg-blue-900 text-white border-blue-900 shadow-lg shadow-blue-900/20' 
                : 'bg-white text-slate-500 border-slate-100 hover:border-blue-200 hover:text-blue-900 shadow-sm'
              }`}
            >
              {acc}
            </button>
          ))}
        </div>
      </div>

      <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
        {activeTab === Tab.DASHBOARD && <Dashboard transactions={filteredTransactions} />}
        {activeTab === Tab.CONTAS_PAGAR && (
          <TransactionTable 
            type="PAGAR" 
            transactions={filteredTransactions.filter(t => t.type === 'PAGAR')} 
            costCenters={costCenters}
            onAdd={async t => { await supabase.from('transactions').insert(t); fetchData(); }} 
            onUpdate={async t => { await supabase.from('transactions').update(t).eq('id', t.id); fetchData(); }} 
            onDelete={async ids => { await supabase.from('transactions').delete().in('id', ids); fetchData(); }} 
          />
        )}
        {activeTab === Tab.CONTAS_RECEBER && (
          <TransactionTable 
            type="RECEBER" 
            transactions={filteredTransactions.filter(t => t.type === 'RECEBER')} 
            costCenters={costCenters}
            onAdd={async t => { await supabase.from('transactions').insert(t); fetchData(); }} 
            onUpdate={async t => { await supabase.from('transactions').update(t).eq('id', t.id); fetchData(); }} 
            onDelete={async ids => { await supabase.from('transactions').delete().in('id', ids); fetchData(); }} 
          />
        )}
        {activeTab === Tab.CENTRO_CUSTO && <CostCentersView costCenters={costCenters} onSave={async cc => { await supabase.from('cost_centers').upsert({id: cc.id, nome: cc.nome, tipo: cc.tipo, sub_itens: cc.subItens}); fetchData(); }} onDelete={async id => { await supabase.from('cost_centers').delete().eq('id', id); fetchData(); }} />}
        {activeTab === Tab.FLUXO_CAIXA && <CashFlow transactions={filteredTransactions} />}
        {activeTab === Tab.DETALHES && <Details transactions={filteredTransactions} />}
        {activeTab === Tab.PLAN_CREDENCIAS && <CredentialsManager users={appUsers} onUpdateUsers={async nu => { for(const u of nu) { await supabase.from('users').upsert(u); } fetchData(); }} />}
      </div>
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Transaction, TransactionType, Status, CostCenter } from '../types';

interface TransactionTableProps {
  type: TransactionType;
  transactions: Transaction[];
  costCenters: CostCenter[];
  onAdd: (transaction: Transaction) => void;
  onUpdate: (transaction: Transaction) => void;
  onDelete: (ids: string[]) => void;
}

const TransactionTable: React.FC<TransactionTableProps> = ({ type, transactions, costCenters, onAdd, onUpdate, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [formData, setFormData] = useState({
    vencimento: new Date().toISOString().split('T')[0],
    pagamento: '',
    descricao: '',
    valor: '',
    formaPagamento: 'PIX',
    centroCusto: '',
    subItem: '',
    status: 'PENDENTE' as Status,
    conta: 'GERAL'
  });

  // Filtrar centros de custo pelo tipo (Receita ou Despesa) baseado na aba atual
  const availableCostCenters = costCenters.filter(cc => cc.tipo === (type === 'RECEBER' ? 'RECEITA' : 'DESPESA'));

  // Obter sub-itens do centro de custo selecionado vindo da estrutura do banco
  const availableSubItems = availableCostCenters.find(cc => cc.nome === formData.centroCusto)?.subItens || [];

  const filtered = transactions.filter(t => {
    const search = searchTerm.toLowerCase();
    return (
      t.descricao.toLowerCase().includes(search) ||
      t.centroCusto.toLowerCase().includes(search) ||
      (t.conta || '').toLowerCase().includes(search)
    );
  });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const transactionData: Transaction = {
      id: editingId || crypto.randomUUID(),
      type: type,
      vencimento: formData.vencimento,
      pagamento: formData.status !== 'PENDENTE' ? (formData.pagamento || formData.vencimento) : undefined,
      descricao: formData.descricao,
      valor: parseFloat(formData.valor),
      formaPagamento: formData.formaPagamento,
      status: formData.status,
      centroCusto: formData.centroCusto,
      subItem: formData.subItem,
      conta: formData.conta
    };

    if (editingId) onUpdate(transactionData);
    else onAdd(transactionData);

    setIsModalOpen(false);
    resetForm();
  };

  const resetForm = () => {
    setFormData({
      vencimento: new Date().toISOString().split('T')[0],
      pagamento: '',
      descricao: '',
      valor: '',
      formaPagamento: 'PIX',
      centroCusto: '',
      subItem: '',
      status: 'PENDENTE',
      conta: 'GERAL'
    });
    setEditingId(null);
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 overflow-hidden border border-slate-100">
      <div className="p-5 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-4 bg-slate-50/50">
        <h2 className="text-xl font-black text-blue-900 uppercase tracking-tighter">
          {type === 'PAGAR' ? 'Contas a Pagar' : 'Contas a Receber'}
        </h2>
        <div className="flex items-center gap-2">
           <button onClick={() => { resetForm(); setIsModalOpen(true); }} className="bg-blue-900 text-white px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 hover:bg-blue-800 transition-all shadow-lg shadow-blue-900/20">
             <i className="fa-solid fa-plus"></i> Novo Registro
           </button>
           <button onClick={() => onDelete(selectedIds)} disabled={selectedIds.length === 0} className={`px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 transition-all ${selectedIds.length > 0 ? 'bg-red-500 text-white shadow-lg shadow-red-500/20' : 'bg-slate-100 text-slate-400 cursor-not-allowed'}`}>
             <i className="fa-solid fa-trash-can"></i> {selectedIds.length > 0 ? `Excluir (${selectedIds.length})` : 'Excluir'}
           </button>
        </div>
      </div>

      <div className="p-4 bg-white border-b border-slate-50">
        <div className="relative group">
          <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-900 transition-colors"></i>
          <input 
            type="text" 
            placeholder="Pesquisar por descrição, conta, categoria..." 
            className="w-full pl-12 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-4 focus:ring-blue-900/5 focus:border-blue-900 outline-none text-sm transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest">
              <th className="p-5 w-12 text-center">
                <input type="checkbox" onChange={(e) => e.target.checked ? setSelectedIds(filtered.map(t => t.id)) : setSelectedIds([])} />
              </th>
              <th className="p-5">Data</th>
              <th className="p-5">Descrição / Conta</th>
              <th className="p-5 text-right">Valor</th>
              <th className="p-5">Categoria</th>
              <th className="p-5">Status</th>
              <th className="p-5 text-center">Ações</th>
            </tr>
          </thead>
          <tbody className="text-sm divide-y divide-slate-100">
            {filtered.map((t) => (
              <tr key={t.id} className={`${selectedIds.includes(t.id) ? 'bg-blue-50/50' : 'hover:bg-slate-50/30'} transition-colors group`}>
                <td className="p-5 text-center">
                   <input type="checkbox" checked={selectedIds.includes(t.id)} onChange={() => setSelectedIds(prev => prev.includes(t.id) ? prev.filter(i => i !== t.id) : [...prev, t.id])} />
                </td>
                <td className="p-5 font-bold text-slate-600">{new Date(t.vencimento).toLocaleDateString('pt-BR')}</td>
                <td className="p-5">
                  <div className="font-black text-blue-900 uppercase tracking-tight leading-none mb-1">{t.descricao}</div>
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] bg-slate-100 px-2 py-0.5 rounded font-black text-slate-500 uppercase">{t.conta || 'GERAL'}</span>
                    <span className="text-[9px] text-slate-400 uppercase font-bold">{t.formaPagamento}</span>
                  </div>
                </td>
                <td className={`p-5 text-right font-black text-lg ${type === 'PAGAR' ? 'text-red-500' : 'text-emerald-600'}`}>
                   R$ {t.valor.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                </td>
                <td className="p-5">
                  <div className="text-[10px] uppercase font-black text-slate-400 leading-none">{t.centroCusto}</div>
                  <div className="text-[9px] font-bold text-slate-300 uppercase">{t.subItem}</div>
                </td>
                <td className="p-5">
                  <span className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest ${
                    t.status === 'PENDENTE' ? 'bg-amber-100 text-amber-700' : 'bg-emerald-100 text-emerald-700'
                  }`}>
                    {t.status}
                  </span>
                </td>
                <td className="p-5 text-center">
                  <button onClick={() => {
                    setEditingId(t.id);
                    setFormData({
                      vencimento: t.vencimento, pagamento: t.pagamento || '', descricao: t.descricao,
                      valor: t.valor.toString(), formaPagamento: t.formaPagamento, centroCusto: t.centroCusto,
                      subItem: t.subItem, status: t.status, conta: t.conta || 'GERAL'
                    });
                    setIsModalOpen(true);
                  }} className="text-blue-900 hover:bg-blue-50 p-3 rounded-xl transition-all"><i className="fa-solid fa-pen-to-square"></i></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-blue-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl overflow-hidden animate-in fade-in zoom-in duration-300 border border-white/20">
            <div className="bg-blue-900 p-6 flex justify-between items-center text-white">
              <div>
                <h3 className="text-xl font-black uppercase tracking-tighter">
                  {editingId ? 'Editar Lançamento' : 'Novo Lançamento'}
                </h3>
                <p className="text-[10px] font-bold text-white/50 uppercase tracking-widest">{type === 'PAGAR' ? 'Contas a Pagar' : 'Contas a Receber'}</p>
              </div>
              <button onClick={() => setIsModalOpen(false)} className="bg-white/10 w-10 h-10 rounded-full flex items-center justify-center hover:bg-white/20 transition-all font-bold text-xl">&times;</button>
            </div>

            <form onSubmit={handleSave} className="p-6 space-y-5 overflow-y-auto max-h-[85vh]">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Data Vencimento</label>
                  <input type="date" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 transition-all text-slate-700 font-medium" value={formData.vencimento} onChange={e => setFormData({...formData, vencimento: e.target.value})} required />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Conta / Banco</label>
                  <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 transition-all font-bold text-slate-700" value={formData.conta} onChange={e => setFormData({...formData, conta: e.target.value})}>
                    <option value="SANTANDER">SANTANDER</option>
                    <option value="NUBANK">NUBANK</option>
                    <option value="CAIXA">CAIXA</option>
                    <option value="INTER">INTER</option>
                    <option value="BRADESCO">BRADESCO</option>
                    <option value="GERAL">GERAL / DINHEIRO</option>
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Descrição do Lançamento</label>
                <input type="text" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 uppercase font-medium text-slate-700" placeholder="Ex: PAGAMENTO FORNECEDOR X" value={formData.descricao} onChange={e => setFormData({...formData, descricao: e.target.value.toUpperCase()})} required />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                   <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Valor (R$)</label>
                   <input type="number" step="0.01" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-black text-lg text-blue-900" placeholder="0,00" value={formData.valor} onChange={e => setFormData({...formData, valor: e.target.value})} required />
