                <div>
                   <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Status do Pagamento</label>
                   <select className={`w-full p-3 border rounded-xl outline-none font-black text-xs transition-colors ${formData.status === 'PENDENTE' ? 'border-amber-200 bg-amber-50 text-amber-700' : 'border-emerald-200 bg-emerald-50 text-emerald-700'}`} value={formData.status} onChange={e => setFormData({...formData, status: e.target.value as Status})}>
                     <option value="PENDENTE">🟡 PENDENTE</option>
                     {type === 'PAGAR' ? <option value="PAGO">🟢 PAGO</option> : <option value="RECEBIDO">🟢 RECEBIDO</option>}
