  const [activeTab, setActiveTab] = useState<Tab | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [appUsers, setAppUsers] = useState<User[]>([]);
  const [costCenters, setCostCenters] = useState<CostCenter[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [errorType, setErrorType] = useState<'SCHEMA_HIDDEN' | 'TABLES_MISSING' | null>(null);
  const [activeAccount, setActiveAccount] = useState<string>('TODAS');

  const fetchData = async () => {
    setIsLoading(true);
    setErrorType(null);
    try {
      const { data: usersData, error: uErr, status } = await supabase.from('users').select('*');

      if (uErr) {
        console.error("Erro Supabase:", uErr);
        if (uErr.code === 'PGRST106' || uErr.message.includes('Invalid schema')) {
          setErrorType('SCHEMA_HIDDEN');
          setIsLoading(false);
          return;
        }
        if (uErr.code === '42P01' || status === 406) {
          setErrorType('TABLES_MISSING');
          setIsLoading(false);
          return;
        }
      }

      const [transactionsRes, costCentersRes] = await Promise.all([
        supabase.from('transactions').select('*').order('vencimento', { ascending: false }),
        supabase.from('cost_centers').select('*').order('nome')
      ]);

      let currentUsers = (usersData || []) as User[];
      const hasAdmin = currentUsers.some(u => u.login === 'admin');

      if (!hasAdmin && !uErr) {
        const adminUser: User = {
          login: 'admin',
          senha: '123',
          email: 'admin@multiplan.com',
          approved: true, // Admin sempre aprovado
          permissions: {
            centroCusto: true, contasPagar: true, contasReceber: true,
            dashboard: true, fluxoCaixa: true, detalhes: true, planCredencias: true
          }
        };
        await supabase.from('users').insert(adminUser);
        currentUsers = [...currentUsers, adminUser];
      }

      setAppUsers(currentUsers);
      if (transactionsRes.data) setTransactions(transactionsRes.data);
      if (costCentersRes.data) {
        setCostCenters(costCentersRes.data.map(cc => ({
          id: cc.id, nome: cc.nome, tipo: cc.tipo, subItens: cc.sub_itens || []
        })));
      }
    } catch (error) {
      console.error('Erro crítico:', error);
      setErrorType('TABLES_MISSING');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const accounts = useMemo(() => {
    const unique = Array.from(new Set(transactions.map(t => t.conta || 'GERAL')));
    return ['TODAS', ...unique.sort()];
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    if (activeAccount === 'TODAS') return transactions;
    return transactions.filter(t => (t.conta || 'GERAL') === activeAccount);
  }, [transactions, activeAccount]);

  const handleLogin = (login: string, pass: string) => {
    const foundUser = appUsers.find(u => u.login === login && u.senha === pass);
    if (foundUser) {
      if (foundUser.approved === false) {
        alert('Sua solicitação de acesso está aguardando aprovação do administrador.');
        return;
      }
      setUser(foundUser);
      if (foundUser.permissions.dashboard) setActiveTab(Tab.DASHBOARD);
      else setActiveTab(Tab.CONTAS_PAGAR);
    } else {
      alert('Login ou senha inválidos!');
    }
  };

  const handleRegister = async (login: string, email: string, pass: string) => {
    const newUser: User = {
      login, senha: pass, email,
      approved: false, // Novos usuários precisam de aprovação
      permissions: { centroCusto: false, contasPagar: false, contasReceber: false, dashboard: false, fluxoCaixa: false, detalhes: false, planCredencias: false }
    };
    const { error } = await supabase.from('users').insert(newUser);
    if (error) {
      alert('Erro ao solicitar acesso. Este login já pode existir.');
      return false;
    }
    await fetchData();
    alert('Sua solicitação foi enviada com sucesso! Aguarde a aprovação do administrador.');
    return true;
  };

  if (errorType === 'SCHEMA_HIDDEN') {
    return (
      <div className="min-h-screen bg-slate-900 text-white p-8 flex flex-col items-center justify-center font-sans">
        <div className="max-w-2xl w-full space-y-8 animate-in fade-in zoom-in duration-500">
          <div className="text-center space-y-4">
            <i className="fa-solid fa-lock-open text-6xl text-orange-500 mb-4 animate-bounce"></i>
            <h1 className="text-3xl font-black uppercase tracking-tighter">Esquema Bloqueado (PGRST106)</h1>
            <div className="bg-orange-500/10 border border-orange-500/20 p-4 rounded-xl text-orange-200 text-sm">
              Sua API do Supabase não está configurada para mostrar o esquema <strong>public</strong>.
            </div>
          </div>
          <button onClick={fetchData} className="w-full bg-blue-600 hover:bg-blue-500 text-white font-black py-4 rounded-xl uppercase tracking-widest transition-all shadow-xl flex items-center justify-center gap-3">
            <i className="fa-solid fa-sync"></i> Recarregar Configuração
          </button>
        </div>
      </div>
    );
  }

  if (errorType === 'TABLES_MISSING') {
    return (
      <div className="min-h-screen bg-slate-900 text-white p-8 flex flex-col items-center justify-center font-sans">
        <div className="max-w-3xl w-full space-y-8 animate-in fade-in zoom-in duration-500">
          <div className="text-center space-y-4">
            <i className="fa-solid fa-database text-6xl text-blue-500 mb-4"></i>
            <h1 className="text-3xl font-black uppercase tracking-tighter">Tabelas não encontradas</h1>
          </div>
          <button onClick={fetchData} className="w-full bg-blue-600 hover:bg-blue-500 text-white font-black py-4 rounded-xl uppercase tracking-widest transition-all shadow-xl flex items-center justify-center gap-3">
            <i className="fa-solid fa-sync"></i> Tentar novamente
          </button>
        </div>
      </div>
    );
  }

  if (isLoading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-white text-blue-900 gap-4">
      <i className="fa-solid fa-circle-notch fa-spin text-4xl"></i>
      <span className="text-[10px] font-black uppercase tracking-[0.2em] opacity-50">Sincronizando Multiplan...</span>
    </div>
  );

  if (!user) return <Login onLogin={handleLogin} onRegister={handleRegister} />;

  return (
    <Layout user={user} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={() => setUser(null)}>
      <div className="mb-6">
        <div className="flex items-center gap-4 mb-3">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <i className="fa-solid fa-building-columns"></i> Filtro por Conta
          </h3>
          <div className="h-px bg-slate-200 flex-1"></div>
        </div>
        <div className="flex items-center gap-2 overflow-x-auto pb-2 scrollbar-hide">
          {accounts.map(acc => (
            <button
              key={acc}
              onClick={() => setActiveAccount(acc)}
              className={`px-5 py-2 rounded-xl text-xs font-bold transition-all whitespace-nowrap border-2 ${
                activeAccount === acc 
                ? 'bg-blue-900 text-white border-blue-900 shadow-lg shadow-blue-900/20' 
                : 'bg-white text-slate-500 border-slate-100 hover:border-blue-200 hover:text-blue-900 shadow-sm'
              }`}
            >
              {acc}
            </button>
          ))}
        </div>
      </div>

      <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
        {activeTab === Tab.DASHBOARD && <Dashboard transactions={filteredTransactions} />}
        {activeTab === Tab.CONTAS_PAGAR && (
          <TransactionTable 
            type="PAGAR" 
            transactions={filteredTransactions.filter(t => t.type === 'PAGAR')} 
            costCenters={costCenters}
            onAdd={async t => { await supabase.from('transactions').insert(t); fetchData(); }} 
            onUpdate={async t => { await supabase.from('transactions').update(t).eq('id', t.id); fetchData(); }} 
            onDelete={async ids => { await supabase.from('transactions').delete().in('id', ids); fetchData(); }} 
          />
        )}
        {activeTab === Tab.CONTAS_RECEBER && (
          <TransactionTable 
            type="RECEBER" 
            transactions={filteredTransactions.filter(t => t.type === 'RECEBER')} 
            costCenters={costCenters}
            onAdd={async t => { await supabase.from('transactions').insert(t); fetchData(); }} 
            onUpdate={async t => { await supabase.from('transactions').update(t).eq('id', t.id); fetchData(); }} 
            onDelete={async ids => { await supabase.from('transactions').delete().in('id', ids); fetchData(); }} 
          />
        )}
        {activeTab === Tab.CENTRO_CUSTO && <CostCentersView costCenters={costCenters} onSave={async cc => { await supabase.from('cost_centers').upsert({id: cc.id, nome: cc.nome, tipo: cc.tipo, sub_itens: cc.subItens}); fetchData(); }} onDelete={async id => { await supabase.from('cost_centers').delete().eq('id', id); fetchData(); }} />}
        {activeTab === Tab.FLUXO_CAIXA && <CashFlow transactions={filteredTransactions} />}
        {activeTab === Tab.DETALHES && <Details transactions={filteredTransactions} costCenters={costCenters} />}
        {activeTab === Tab.PLAN_CREDENCIAS && <CredentialsManager users={appUsers} onUpdateUsers={async nu => { for(const u of nu) { await supabase.from('users').upsert(u); } fetchData(); }} />}
      </div>
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';

interface LoginProps {
  onLogin: (user: string, pass: string) => void;
  onRegister: (login: string, email: string, pass: string) => Promise<boolean>;
}

const Login: React.FC<LoginProps> = ({ onLogin, onRegister }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [login, setLogin] = useState('');
  const [email, setEmail] = useState('');
  const [senha, setSenha] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isRegistering) {
      setLoading(true);
      const success = await onRegister(login, email, senha);
      setLoading(false);
      if (success) {
        setIsRegistering(false);
        setSenha('');
      }
    } else {
      onLogin(login, senha);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#f8fafc] font-sans p-4">
      <div className="bg-white p-10 rounded-lg shadow-2xl w-full max-w-[420px] transition-all duration-500 border-t-8 border-[#1e3a8a]">
        <div className="text-center mb-10">
          <h1 className="text-4xl font-black text-[#1e3a8a] uppercase tracking-tighter">MULTIPLAN</h1>
          <div className="w-12 h-1 bg-[#1e3a8a] mx-auto rounded mt-1"></div>
        </div>

        <div className="mb-8 text-center">
          <h2 className="text-2xl font-black text-[#1e3a8a] mb-1">
            {isRegistering ? 'Solicitar Acesso' : 'Bem Vindo'}
          </h2>
          <p className="text-xs font-medium text-slate-400">
            {isRegistering ? 'Preencha os dados para solicitar seu acesso.' : 'Entre com suas credenciais abaixo.'}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-1 group">
            <div className="flex items-center justify-between">
               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest" htmlFor="login">Login</label>
            </div>
            <input
              id="login"
              type="text"
              value={login}
              onChange={(e) => setLogin(e.target.value)}
              className="w-full bg-transparent border-b-2 border-slate-100 py-2.5 text-sm font-bold text-slate-700 outline-none focus:border-[#1e3a8a] transition-all placeholder:text-slate-200"
              placeholder="Usuario"
              required
            />
          </div>

          {isRegistering && (
            <div className="space-y-1 animate-in fade-in slide-in-from-top-2 duration-300">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest" htmlFor="email">E-mail</label>
              <input
                id="email"
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full bg-transparent border-b-2 border-slate-100 py-2.5 text-sm font-bold text-slate-700 outline-none focus:border-[#1e3a8a] transition-all placeholder:text-slate-200"
                placeholder="email@multiplan.com"
                required
              />
            </div>
          )}

          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest" htmlFor="senha">Senha</label>
            <input
              id="senha"
              type="password"
              value={senha}
              onChange={(e) => setSenha(e.target.value)}
              className="w-full bg-transparent border-b-2 border-slate-100 py-2.5 text-sm font-bold text-slate-700 outline-none focus:border-[#1e3a8a] transition-all placeholder:text-slate-200"
              placeholder="••••••"
              required
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-[#1e3a8a] hover:bg-[#152a65] text-white font-black py-4 px-4 rounded-lg transition-all duration-300 uppercase text-xs tracking-[0.2em] shadow-xl shadow-blue-900/20 flex items-center justify-center gap-3 active:scale-95"
          >
            {loading && <i className="fa-solid fa-circle-notch fa-spin"></i>}
            {isRegistering ? 'Enviar Solicitação' : 'Entrar'}
          </button>
        </form>

        <div className="mt-12 pt-8 border-t border-slate-50 text-center">
          <button 
            onClick={() => setIsRegistering(!isRegistering)}
            className="text-[10px] font-black text-[#1e3a8a] hover:text-[#152a65] transition-colors uppercase tracking-[0.1em] flex items-center justify-center gap-2 mx-auto"
          >
            {isRegistering ? (
               <>TENHO ACESSO? <span className="text-orange-500">ENTRAR AGORA</span></>
            ) : (
               <>NÃO TEM ACESSO? <span className="text-orange-500">SOLICITAR AGORA</span></>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState } from 'react';
import { User } from '../types';

interface CredentialsManagerProps {
  users: User[];
  onUpdateUsers: (users: User[]) => void;
}

const CredentialsManager: React.FC<CredentialsManagerProps> = ({ users, onUpdateUsers }) => {
  const [newLogin, setNewLogin] = useState('');
  const [newSenha, setNewSenha] = useState('');
  const [newEmail, setNewEmail] = useState('');
  const [isAdding, setIsAdding] = useState(false);

  const pendingUsers = users.filter(u => u.approved === false);
  const activeUsers = users.filter(u => u.approved === true);

  const handleAddUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newLogin || !newSenha || !newEmail) {
      alert('Por favor, preencha Login, Senha e E-mail.');
      return;
    }

    const newUser: User = {
      login: newLogin,
      senha: newSenha,
      email: newEmail,
      approved: true, // Adicionado manualmente pelo admin já nasce aprovado
      permissions: {
        centroCusto: false,
        contasPagar: false,
        contasReceber: false,
        dashboard: false,
        fluxoCaixa: false,
        detalhes: false,
        planCredencias: false
      }
    };

    onUpdateUsers([...users, newUser]);
    setNewLogin('');
    setNewSenha('');
    setNewEmail('');
    setIsAdding(false);
  };

  const handleApprove = (login: string) => {
    const updatedUsers = users.map(u => {
      if (u.login === login) {
        return { ...u, approved: true };
      }
      return u;
    });
    onUpdateUsers(updatedUsers);
  };

  const togglePermission = (login: string, permission: keyof User['permissions']) => {
    const updatedUsers = users.map(u => {
      if (u.login === login) {
        return {
          ...u,
          permissions: {
            ...u.permissions,
            [permission]: !u.permissions[permission]
          }
        };
      }
      return u;
    });
    onUpdateUsers(updatedUsers);
  };

  const removeUser = (login: string) => {
    if (login === 'admin') {
      alert('Não é possível remover o administrador.');
      return;
    }
    if (confirm(`Deseja remover o usuário ${login}?`)) {
      onUpdateUsers(users.filter(u => u.login !== login));
    }
  };

  return (
    <div className="space-y-8">
      {/* ÁREA DE APROVAÇÃO */}
      {pendingUsers.length > 0 && (
        <div className="bg-orange-50 p-6 rounded-2xl border-2 border-orange-200 animate-in fade-in slide-in-from-top-4 duration-500">
           <div className="flex items-center gap-3 mb-6">
              <div className="w-10 h-10 bg-orange-500 text-white rounded-xl flex items-center justify-center shadow-lg">
                 <i className="fa-solid fa-user-clock"></i>
              </div>
              <div>
                <h2 className="text-xl font-black text-orange-900 uppercase tracking-tighter leading-none">Aprovação de Acessos</h2>
                <p className="text-[10px] font-bold text-orange-600 uppercase tracking-widest mt-1">Existem {pendingUsers.length} solicitações pendentes</p>
              </div>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {pendingUsers.map(u => (
                <div key={u.login} className="bg-white p-4 rounded-xl border border-orange-100 shadow-sm flex flex-col justify-between group">
                   <div className="mb-4">
                      <p className="text-xs font-black text-slate-800 uppercase">{u.login}</p>
                      <p className="text-[10px] text-slate-400 font-bold truncate">{u.email}</p>
                   </div>
                   <div className="flex gap-2">
                      <button 
                        onClick={() => handleApprove(u.login)}
                        className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all"
                      >
                        Aprovar
                      </button>
                      <button 
                        onClick={() => removeUser(u.login)}
                        className="bg-slate-100 hover:bg-red-100 hover:text-red-600 text-slate-400 py-2 px-3 rounded-lg transition-all"
                      >
                        <i className="fa-solid fa-trash-can"></i>
                      </button>
                   </div>
                </div>
              ))}
           </div>
        </div>
      )}

      {/* GESTÃO DE USUÁRIOS ATIVOS */}
      <div className="bg-white p-6 rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-100 space-y-6">
        <div className="flex items-center justify-between border-b border-slate-100 pb-4">
          <div>
            <h2 className="text-xl font-black text-blue-900 uppercase tracking-tighter">Usuários Ativos</h2>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Controle total de permissões e acessos</p>
          </div>
          <button 
            onClick={() => setIsAdding(!isAdding)}
            className="bg-blue-900 text-white px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 hover:bg-blue-800 transition-all shadow-lg shadow-blue-900/20"
          >
            <i className={`fa-solid ${isAdding ? 'fa-times' : 'fa-plus'}`}></i>
            {isAdding ? 'Cancelar' : 'Cadastrar Manual'}
          </button>
        </div>

        {isAdding && (
          <form onSubmit={handleAddUser} className="bg-slate-50 p-6 rounded-2xl border border-slate-200 grid grid-cols-1 md:grid-cols-4 gap-4 items-end animate-in fade-in slide-in-from-top-2">
            <div>
              <label className="block text-[10px] font-black text-blue-900 uppercase tracking-widest mb-1.5">Login</label>
              <input 
                type="text" 
                className="w-full p-3 text-xs font-bold border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5" 
                placeholder="Usuario"
                value={newLogin}
                onChange={(e) => setNewLogin(e.target.value)}
                required
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-blue-900 uppercase tracking-widest mb-1.5">E-mail</label>
              <input 
                type="email" 
                className="w-full p-3 text-xs font-bold border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5" 
                placeholder="email@multiplan.com"
                value={newEmail}
                onChange={(e) => setNewEmail(e.target.value)}
                required
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-blue-900 uppercase tracking-widest mb-1.5">Senha</label>
              <input 
                type="password" 
                className="w-full p-3 text-xs font-bold border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5" 
                placeholder="••••••"
                value={newSenha}
                onChange={(e) => setNewSenha(e.target.value)}
                required
              />
            </div>
            <button type="submit" className="bg-orange-500 text-white py-3.5 rounded-xl text-xs font-black uppercase tracking-widest hover:bg-orange-600 transition-all shadow-lg shadow-orange-500/20">
              Salvar Usuário
            </button>
          </form>
        )}

        <div className="overflow-x-auto rounded-xl border border-slate-100">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-blue-900 text-white text-[10px] uppercase font-black tracking-widest">
                <th className="p-4 border-r border-blue-800">Login / E-mail</th>
                <th className="p-4 border-r border-blue-800 text-center">Dashboard</th>
                <th className="p-4 border-r border-blue-800 text-center">Contas Pagar</th>
                <th className="p-4 border-r border-blue-800 text-center">Contas Receber</th>
                <th className="p-4 border-r border-blue-800 text-center">Fluxo Caixa</th>
                <th className="p-4 border-r border-blue-800 text-center">Estrutura</th>
                <th className="p-4 border-r border-blue-800 text-center">Relatórios</th>
                <th className="p-4 border-r border-blue-800 text-center">Usuários</th>
                <th className="p-4 text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="text-[10px]">
              {activeUsers.map((u, idx) => (
                <tr key={u.login} className={`${idx % 2 === 0 ? 'bg-white' : 'bg-slate-50/50'} hover:bg-blue-50/30 transition-colors`}>
                  <td className="p-4 border-b border-slate-100">
                    <div className="font-black text-blue-900 uppercase tracking-tight">{u.login}</div>
                    <div className="text-[9px] text-slate-400 font-bold lowercase">{u.email || '—'}</div>
                  </td>
                  {[
                    'dashboard', 'contasPagar', 'contasReceber', 
                    'fluxoCaixa', 'centroCusto', 'detalhes', 'planCredencias'
                  ].map(perm => (
                    <td key={perm} className="p-4 border-b border-slate-100 text-center">
                      <input 
                        type="checkbox" 
                        checked={u.permissions[perm as keyof User['permissions']]} 
                        disabled={u.login === 'admin' && perm === 'planCredencias'}
                        onChange={() => togglePermission(u.login, perm as keyof User['permissions'])}
                        className="w-4 h-4 cursor-pointer accent-blue-900"
                      />
                    </td>
                  ))}
                  <td className="p-4 border-b border-slate-100 text-center">
                    <button 
                      onClick={() => removeUser(u.login)}
                      disabled={u.login === 'admin'}
                      className="text-slate-300 hover:text-red-500 disabled:opacity-0 transition-colors"
                    >
                      <i className="fa-solid fa-trash-can"></i>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default CredentialsManager;

import React, { useMemo } from 'react';
import { Transaction } from '../types';

interface CashFlowProps {
  transactions: Transaction[];
}

const CashFlow: React.FC<CashFlowProps> = ({ transactions }) => {
  const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const data = useMemo(() => {
    // Obter todos os centros de custo únicos presentes nas transações
    // Fix: Explicitly typing as string[] to ensure 'cat' in .map is not 'unknown'
    const incomeCategories: string[] = Array.from(new Set<string>(transactions.filter(t => t.type === 'RECEBER').map(t => t.centroCusto))).sort();
    const expenseCategories: string[] = Array.from(new Set<string>(transactions.filter(t => t.type === 'PAGAR').map(t => t.centroCusto))).sort();

    const getValuesForCategory = (category: string, type: 'RECEBER' | 'PAGAR') => {
      const values = new Array(12).fill(0);
      transactions.filter(t => t.type === type && t.centroCusto === category).forEach(t => {
        const month = new Date(t.vencimento).getMonth();
        values[month] += t.valor;
      });
      return values;
    };

    const incomeRows = incomeCategories.map((cat: string) => ({
      label: cat,
      type: 'IN',
      values: getValuesForCategory(cat, 'RECEBER')
    }));

    const expenseRows = expenseCategories.map((cat: string) => ({
      label: cat,
      type: 'OUT',
      values: getValuesForCategory(cat, 'PAGAR')
    }));

    // Cálculos de totais por mês
    const totalInByMonth = new Array(12).fill(0);
    const totalOutByMonth = new Array(12).fill(0);

    incomeRows.forEach(row => row.values.forEach((v, i) => totalInByMonth[i] += v));
    expenseRows.forEach(row => row.values.forEach((v, i) => totalOutByMonth[i] += v));

    const saldoByMonth = totalInByMonth.map((tin, i) => tin - totalOutByMonth[i]);

    return { incomeRows, expenseRows, totalInByMonth, totalOutByMonth, saldoByMonth };
  }, [transactions]);

  return (
    <div className="bg-white p-6 rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-100">
       <div className="mb-6 flex items-center justify-between">
          <div>
            <h2 className="text-xl font-black text-blue-900 uppercase tracking-tighter">Fluxo de Caixa Real</h2>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Soma de movimentações por categoria</p>
          </div>
          <div className="flex gap-2">
            <button onClick={() => window.location.reload()} className="bg-slate-100 p-2.5 rounded-xl text-slate-500 hover:bg-blue-900 hover:text-white transition-all"><i className="fa-solid fa-rotate"></i></button>
            <button className="bg-slate-100 p-2.5 rounded-xl text-slate-500 hover:bg-emerald-600 hover:text-white transition-all"><i className="fa-solid fa-file-excel"></i></button>
          </div>
       </div>

       <div className="overflow-x-auto rounded-xl border border-slate-100">
         <table className="w-full text-[10px] border-collapse min-w-[1400px]">
            <thead>
              <tr className="bg-blue-900 text-white font-black uppercase tracking-widest">
                <th className="p-4 text-left sticky left-0 bg-blue-900 z-10 min-w-[220px]">Centro de Custo</th>
                {months.map(m => <th key={m} className="p-4 text-right border-l border-blue-800/50">{m}</th>)}
                <th className="p-4 text-right border-l border-blue-800/50 bg-blue-950">Total Anual</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {/* ENTRADAS */}
              <tr className="bg-emerald-50/50 font-black text-emerald-700">
                <td className="p-4 sticky left-0 bg-emerald-50/50 z-10">TOTAL DE ENTRADAS (+)</td>
                {data.totalInByMonth.map((v, i) => <td key={i} className="p-4 text-right">R$ {v.toLocaleString('pt-BR', {minimumFractionDigits: 2})}</td>)}
                <td className="p-4 text-right bg-emerald-100">R$ {data.totalInByMonth.reduce((a,b)=>a+b,0).toLocaleString('pt-BR', {minimumFractionDigits: 2})}</td>
              </tr>
              {data.incomeRows.map((row, i) => (
                <tr key={i} className="hover:bg-slate-50 transition-colors group">
                  <td className="p-4 sticky left-0 bg-white group-hover:bg-slate-50 z-10 font-bold text-slate-600 border-r border-slate-50 uppercase">{row.label}</td>
                  {row.values.map((v, j) => (
                    <td key={j} className="p-4 text-right text-emerald-600 font-medium">
                      {v > 0 ? `R$ ${v.toLocaleString('pt-BR', {minimumFractionDigits: 2})}` : '—'}
                    </td>
                  ))}
                  <td className="p-4 text-right font-black text-emerald-700 bg-slate-50/50">
                    R$ {row.values.reduce((a, b) => a + b, 0).toLocaleString('pt-BR', {minimumFractionDigits: 2})}
                  </td>
                </tr>
              ))}

              {/* SAÍDAS */}
              <tr className="bg-orange-50/50 font-black text-orange-700">
                <td className="p-4 sticky left-0 bg-orange-50/50 z-10">TOTAL DE SAÍDAS (-)</td>
                {data.totalOutByMonth.map((v, i) => <td key={i} className="p-4 text-right">R$ {v.toLocaleString('pt-BR', {minimumFractionDigits: 2})}</td>)}
                <td className="p-4 text-right bg-orange-100">R$ {data.totalOutByMonth.reduce((a,b)=>a+b,0).toLocaleString('pt-BR', {minimumFractionDigits: 2})}</td>
              </tr>
              {data.expenseRows.map((row, i) => (
                <tr key={i} className="hover:bg-slate-50 transition-colors group">
                  <td className="p-4 sticky left-0 bg-white group-hover:bg-slate-50 z-10 font-bold text-slate-600 border-r border-slate-50 uppercase">{row.label}</td>
                  {row.values.map((v, j) => (
                    <td key={j} className="p-4 text-right text-orange-600 font-medium">
                      {v > 0 ? `R$ ${v.toLocaleString('pt-BR', {minimumFractionDigits: 2})}` : '—'}
                    </td>
                  ))}
                  <td className="p-4 text-right font-black text-orange-700 bg-slate-50/50">
                    R$ {row.values.reduce((a, b) => a + b, 0).toLocaleString('pt-BR', {minimumFractionDigits: 2})}
                  </td>
                </tr>
              ))}

              {/* SALDO FINAL */}
              <tr className="bg-blue-900 text-white font-black text-xs">
                <td className="p-4 sticky left-0 bg-blue-900 z-10 uppercase tracking-widest">Saldo Operacional (=)</td>
                {data.saldoByMonth.map((v, i) => (
                  <td key={i} className={`p-4 text-right ${v >= 0 ? 'text-emerald-400' : 'text-orange-300'}`}>
                    R$ {v.toLocaleString('pt-BR', {minimumFractionDigits: 2})}
                  </td>
                ))}
                <td className="p-4 text-right bg-blue-950">R$ {data.saldoByMonth.reduce((a,b)=>a+b,0).toLocaleString('pt-BR', {minimumFractionDigits: 2})}</td>
              </tr>
            </tbody>
         </table>
       </div>
    </div>
  );
};

export default CashFlow;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Tab, Transaction, CostCenter } from './types';
import Login from './components/Login';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionTable from './components/TransactionTable';
import CostCentersView from './components/CostCentersView';
import CashFlow from './components/CashFlow';
import Details from './components/Details';
import CredentialsManager from './components/CredentialsManager';
import { supabase } from './lib/supabase';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<Tab | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [appUsers, setAppUsers] = useState<User[]>([]);
  const [costCenters, setCostCenters] = useState<CostCenter[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [errorType, setErrorType] = useState<'SCHEMA_HIDDEN' | 'TABLES_MISSING' | null>(null);
  const [activeAccount, setActiveAccount] = useState<string>('TODAS');

  const fetchData = async () => {
    setIsLoading(true);
    setErrorType(null);
    try {
      const { data: usersData, error: uErr, status } = await supabase.from('users').select('*');

      if (uErr) {
        console.error("Erro Supabase:", uErr);
        if (uErr.code === 'PGRST106' || uErr.message.includes('Invalid schema')) {
          setErrorType('SCHEMA_HIDDEN');
          setIsLoading(false);
          return;
        }
        if (uErr.code === '42P01' || status === 406) {
          setErrorType('TABLES_MISSING');
          setIsLoading(false);
          return;
        }
      }

      const [transactionsRes, costCentersRes] = await Promise.all([
        supabase.from('transactions').select('*').order('vencimento', { ascending: false }),
        supabase.from('cost_centers').select('*').order('nome')
      ]);

      let currentUsers = (usersData || []) as User[];
      const hasAdmin = currentUsers.some(u => u.login === 'admin');

      if (!hasAdmin && !uErr) {
        const adminUser: User = {
          login: 'admin',
          senha: '123',
          email: 'admin@multiplan.com',
          approved: true,
          permissions: {
            centroCusto: true, contasPagar: true, contasReceber: true,
            dashboard: true, fluxoCaixa: true, detalhes: true, planCredencias: true
          }
        };
        await supabase.from('users').insert(adminUser);
        currentUsers = [...currentUsers, adminUser];
      }

      setAppUsers(currentUsers);
      if (transactionsRes.data) setTransactions(transactionsRes.data);
      if (costCentersRes.data) {
        setCostCenters(costCentersRes.data.map(cc => ({
          id: cc.id, nome: cc.nome, tipo: cc.tipo, subItens: cc.sub_itens || []
        })));
      }
    } catch (error) {
      console.error('Erro crítico:', error);
      setErrorType('TABLES_MISSING');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const accounts = useMemo(() => {
    const unique = Array.from(new Set(transactions.map(t => t.conta || 'GERAL')));
    return ['TODAS', ...unique.sort()];
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    if (activeAccount === 'TODAS') return transactions;
    return transactions.filter(t => (t.conta || 'GERAL') === activeAccount);
  }, [transactions, activeAccount]);

  const handleLogin = (login: string, pass: string) => {
    const foundUser = appUsers.find(u => u.login === login && u.senha === pass);
    if (foundUser) {
      if (foundUser.approved === false) {
        alert('Sua solicitação de acesso está aguardando aprovação do administrador.');
        return;
      }
      setUser(foundUser);
      if (foundUser.permissions.dashboard) setActiveTab(Tab.DASHBOARD);
      else setActiveTab(Tab.CONTAS_PAGAR);
    } else {
      alert('Login ou senha inválidos!');
    }
  };

  const handleRegister = async (login: string, email: string, pass: string) => {
    const newUser: User = {
      login, senha: pass, email,
      approved: false,
      permissions: { centroCusto: false, contasPagar: false, contasReceber: false, dashboard: false, fluxoCaixa: false, detalhes: false, planCredencias: false }
    };
    const { error } = await supabase.from('users').insert(newUser);
    if (error) {
      alert('Erro ao solicitar acesso. Este login já pode existir.');
      return false;
    }
    await fetchData();
    alert('Sua solicitação foi enviada com sucesso! Aguarde a aprovação do administrador.');
    return true;
  };

  // Determina se o filtro de conta deve ser exibido
  const showAccountFilter = useMemo(() => {
    return activeTab !== Tab.CENTRO_CUSTO && activeTab !== Tab.PLAN_CREDENCIAS;
  }, [activeTab]);

  if (errorType === 'SCHEMA_HIDDEN') {
    return (
      <div className="min-h-screen bg-slate-900 text-white p-8 flex flex-col items-center justify-center font-sans">
        <div className="max-w-2xl w-full space-y-8 animate-in fade-in zoom-in duration-500">
          <div className="text-center space-y-4">
            <i className="fa-solid fa-lock-open text-6xl text-orange-500 mb-4 animate-bounce"></i>
            <h1 className="text-3xl font-black uppercase tracking-tighter">Esquema Bloqueado (PGRST106)</h1>
            <div className="bg-orange-500/10 border border-orange-500/20 p-4 rounded-xl text-orange-200 text-sm">
              Sua API do Supabase não está configurada para mostrar o esquema <strong>public</strong>.
            </div>
          </div>
          <button onClick={fetchData} className="w-full bg-blue-600 hover:bg-blue-500 text-white font-black py-4 rounded-xl uppercase tracking-widest transition-all shadow-xl flex items-center justify-center gap-3">
            <i className="fa-solid fa-sync"></i> Recarregar Configuração
          </button>
        </div>
      </div>
    );
  }

  if (errorType === 'TABLES_MISSING') {
    return (
      <div className="min-h-screen bg-slate-900 text-white p-8 flex flex-col items-center justify-center font-sans">
        <div className="max-w-3xl w-full space-y-8 animate-in fade-in zoom-in duration-500">
          <div className="text-center space-y-4">
            <i className="fa-solid fa-database text-6xl text-blue-500 mb-4"></i>
            <h1 className="text-3xl font-black uppercase tracking-tighter">Tabelas não encontradas</h1>
          </div>
          <button onClick={fetchData} className="w-full bg-blue-600 hover:bg-blue-500 text-white font-black py-4 rounded-xl uppercase tracking-widest transition-all shadow-xl flex items-center justify-center gap-3">
            <i className="fa-solid fa-sync"></i> Tentar novamente
          </button>
        </div>
      </div>
    );
  }

  if (isLoading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-white text-blue-900 gap-4">
      <i className="fa-solid fa-circle-notch fa-spin text-4xl"></i>
      <span className="text-[10px] font-black uppercase tracking-[0.2em] opacity-50">Sincronizando Multiplan...</span>
    </div>
  );

  if (!user) return <Login onLogin={handleLogin} onRegister={handleRegister} />;

  return (
    <Layout user={user} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={() => setUser(null)}>
      {showAccountFilter && (
        <div className="mb-6 animate-in fade-in slide-in-from-top-2 duration-500">
          <div className="flex items-center gap-4 mb-3">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
              <i className="fa-solid fa-building-columns"></i> Filtro por Conta
            </h3>
            <div className="h-px bg-slate-200 flex-1"></div>
          </div>
          <div className="flex items-center gap-2 overflow-x-auto pb-2 scrollbar-hide">
            {accounts.map(acc => (
              <button
                key={acc}
                onClick={() => setActiveAccount(acc)}
                className={`px-5 py-2 rounded-xl text-xs font-bold transition-all whitespace-nowrap border-2 ${
                  activeAccount === acc 
                  ? 'bg-blue-900 text-white border-blue-900 shadow-lg shadow-blue-900/20' 
                  : 'bg-white text-slate-500 border-slate-100 hover:border-blue-200 hover:text-blue-900 shadow-sm'
                }`}
              >
                {acc}
              </button>
            ))}
          </div>
        </div>
      )}

      <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
        {activeTab === Tab.DASHBOARD && <Dashboard transactions={filteredTransactions} />}
        {activeTab === Tab.CONTAS_PAGAR && (
          <TransactionTable 
            type="PAGAR" 
            transactions={filteredTransactions.filter(t => t.type === 'PAGAR')} 
            costCenters={costCenters}
            onAdd={async t => { await supabase.from('transactions').insert(t); fetchData(); }} 
            onUpdate={async t => { await supabase.from('transactions').update(t).eq('id', t.id); fetchData(); }} 
            onDelete={async ids => { await supabase.from('transactions').delete().in('id', ids); fetchData(); }} 
          />
        )}
        {activeTab === Tab.CONTAS_RECEBER && (
          <TransactionTable 
            type="RECEBER" 
            transactions={filteredTransactions.filter(t => t.type === 'RECEBER')} 
            costCenters={costCenters}
            onAdd={async t => { await supabase.from('transactions').insert(t); fetchData(); }} 
            onUpdate={async t => { await supabase.from('transactions').update(t).eq('id', t.id); fetchData(); }} 
            onDelete={async ids => { await supabase.from('transactions').delete().in('id', ids); fetchData(); }} 
          />
        )}
        {activeTab === Tab.CENTRO_CUSTO && <CostCentersView costCenters={costCenters} onSave={async cc => { await supabase.from('cost_centers').upsert({id: cc.id, nome: cc.nome, tipo: cc.tipo, sub_itens: cc.subItens}); fetchData(); }} onDelete={async id => { await supabase.from('cost_centers').delete().eq('id', id); fetchData(); }} />}
        {activeTab === Tab.FLUXO_CAIXA && <CashFlow transactions={filteredTransactions} />}
        {activeTab === Tab.DETALHES && <Details transactions={filteredTransactions} costCenters={costCenters} />}
        {activeTab === Tab.PLAN_CREDENCIAS && <CredentialsManager users={appUsers} onUpdateUsers={async nu => { for(const u of nu) { await supabase.from('users').upsert(u); } fetchData(); }} />}
      </div>
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { User } from '../types';

interface CredentialsManagerProps {
  users: User[];
  onUpdateUsers: (users: User[]) => void;
}

const CredentialsManager: React.FC<CredentialsManagerProps> = ({ users, onUpdateUsers }) => {
  const [newLogin, setNewLogin] = useState('');
  const [newSenha, setNewSenha] = useState('');
  const [newEmail, setNewEmail] = useState('');
  const [isAdding, setIsAdding] = useState(false);

  // Lógica corrigida para garantir que usuários sem o campo 'approved' sejam considerados ativos (legado)
  const pendingUsers = users.filter(u => u.approved === false);
  const activeUsers = users.filter(u => u.approved === true || u.approved === undefined || u.approved === null);

  const handleAddUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newLogin || !newSenha || !newEmail) {
      alert('Por favor, preencha Login, Senha e E-mail.');
      return;
    }

    const newUser: User = {
      login: newLogin,
      senha: newSenha,
      email: newEmail,
      approved: true, 
      permissions: {
        centroCusto: false,
        contasPagar: false,
        contasReceber: false,
        dashboard: false,
        fluxoCaixa: false,
        detalhes: false,
        planCredencias: false
      }
    };

    onUpdateUsers([...users, newUser]);
    setNewLogin('');
    setNewSenha('');
    setNewEmail('');
    setIsAdding(false);
  };

  const handleApprove = (login: string) => {
    const updatedUsers = users.map(u => {
      if (u.login === login) {
        return { ...u, approved: true };
      }
      return u;
    });
    onUpdateUsers(updatedUsers);
  };

  const togglePermission = (login: string, permission: keyof User['permissions']) => {
    const updatedUsers = users.map(u => {
      if (u.login === login) {
        return {
          ...u,
          permissions: {
            ...u.permissions,
            [permission]: !u.permissions[permission]
          }
        };
      }
      return u;
    });
    onUpdateUsers(updatedUsers);
  };

  const removeUser = (login: string) => {
    if (login === 'admin') {
      alert('Não é possível remover o administrador.');
      return;
    }
    if (confirm(`Deseja remover o usuário ${login}?`)) {
      onUpdateUsers(users.filter(u => u.login !== login));
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* ÁREA DE APROVAÇÃO (Visível apenas quando houver pendentes) */}
      {pendingUsers.length > 0 && (
        <div className="bg-orange-50 p-6 rounded-2xl border-2 border-orange-200 shadow-lg shadow-orange-200/20">
           <div className="flex items-center gap-3 mb-6">
              <div className="w-12 h-12 bg-orange-500 text-white rounded-2xl flex items-center justify-center shadow-lg animate-pulse">
                 <i className="fa-solid fa-user-clock text-xl"></i>
              </div>
              <div>
                <h2 className="text-xl font-black text-orange-900 uppercase tracking-tighter leading-none">Solicitações de Acesso</h2>
                <p className="text-[10px] font-bold text-orange-600 uppercase tracking-widest mt-1">Aprove ou rejeite os pedidos abaixo</p>
              </div>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {pendingUsers.map(u => (
                <div key={u.login} className="bg-white p-5 rounded-2xl border border-orange-100 shadow-sm flex flex-col justify-between group hover:border-orange-300 transition-all">
                   <div className="mb-4">
                      <p className="text-sm font-black text-slate-800 uppercase tracking-tight">{u.login}</p>
                      <p className="text-[10px] text-slate-400 font-bold truncate lowercase">{u.email}</p>
                   </div>
                   <div className="flex gap-2">
                      <button 
                        onClick={() => handleApprove(u.login)}
                        className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-md shadow-emerald-600/10"
                      >
                        Aprovar Acesso
                      </button>
                      <button 
                        onClick={() => removeUser(u.login)}
                        className="bg-slate-100 hover:bg-red-500 hover:text-white text-slate-400 py-2.5 px-4 rounded-xl transition-all"
                        title="Recusar"
                      >
                        <i className="fa-solid fa-trash-can"></i>
                      </button>
                   </div>
                </div>
              ))}
           </div>
        </div>
      )}

      {/* GESTÃO DE USUÁRIOS ATIVOS */}
      <div className="bg-white p-6 rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 space-y-6">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 border-b border-slate-100 pb-6">
          <div>
            <h2 className="text-2xl font-black text-blue-900 uppercase tracking-tighter">Usuários Ativos</h2>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Defina as permissões de cada membro da equipe</p>
          </div>
          <button 
            onClick={() => setIsAdding(!isAdding)}
            className="w-full sm:w-auto bg-blue-900 text-white px-8 py-3.5 rounded-2xl text-xs font-black uppercase tracking-widest flex items-center justify-center gap-3 hover:bg-blue-800 transition-all shadow-xl shadow-blue-900/20 active:scale-95"
          >
            <i className={`fa-solid ${isAdding ? 'fa-times' : 'fa-plus'}`}></i>
            {isAdding ? 'Cancelar' : 'Cadastrar Manual'}
          </button>
        </div>

        {isAdding && (
          <form onSubmit={handleAddUser} className="bg-slate-50 p-6 rounded-2xl border border-slate-200 grid grid-cols-1 md:grid-cols-4 gap-4 items-end animate-in fade-in slide-in-from-top-2 duration-300">
            <div>
              <label className="block text-[10px] font-black text-blue-900 uppercase tracking-widest mb-2">Login de Acesso</label>
              <input 
                type="text" 
                className="w-full p-3.5 text-xs font-bold border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 transition-all" 
                placeholder="Ex: joao.financeiro"
                value={newLogin}
                onChange={(e) => setNewLogin(e.target.value)}
                required
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-blue-900 uppercase tracking-widest mb-2">E-mail</label>
              <input 
                type="email" 
                className="w-full p-3.5 text-xs font-bold border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 transition-all" 
                placeholder="usuario@multiplan.com"
                value={newEmail}
                onChange={(e) => setNewEmail(e.target.value)}
                required
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-blue-900 uppercase tracking-widest mb-2">Senha Provisória</label>
              <input 
                type="password" 
                className="w-full p-3.5 text-xs font-bold border border-slate-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 transition-all" 
                placeholder="••••••"
                value={newSenha}
                onChange={(e) => setNewSenha(e.target.value)}
                required
              />
            </div>
            <button type="submit" className="bg-orange-500 text-white py-4 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-orange-600 transition-all shadow-lg shadow-orange-500/20">
              Salvar Novo Usuário
            </button>
          </form>
        )}

        <div className="overflow-x-auto rounded-2xl border border-slate-100 bg-slate-50/30">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-blue-900 text-white text-[10px] uppercase font-black tracking-widest">
                <th className="p-5 border-r border-blue-800/30">Login / Identificação</th>
                <th className="p-5 border-r border-blue-800/30 text-center">Dashboard</th>
                <th className="p-5 border-r border-blue-800/30 text-center">Contas Pagar</th>
                <th className="p-5 border-r border-blue-800/30 text-center">Contas Receber</th>
                <th className="p-5 border-r border-blue-800/30 text-center">Fluxo Caixa</th>
                <th className="p-5 border-r border-blue-800/30 text-center">Estrutura</th>
                <th className="p-5 border-r border-blue-800/30 text-center">Relatórios</th>
                <th className="p-5 border-r border-blue-800/30 text-center">Usuários</th>
                <th className="p-5 text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="text-sm">
              {activeUsers.length > 0 ? activeUsers.map((u, idx) => (
                <tr key={u.login} className={`${idx % 2 === 0 ? 'bg-white' : 'bg-slate-50/50'} hover:bg-blue-50/50 transition-colors group`}>
                  <td className="p-5 border-b border-slate-100">
                    <div className="font-black text-blue-900 uppercase tracking-tight leading-none mb-1">{u.login}</div>
                    <div className="text-[10px] text-slate-400 font-bold lowercase">{u.email || '—'}</div>
                  </td>

                  {[
                    { key: 'dashboard', label: 'Dashboard' },
                    { key: 'contasPagar', label: 'C. Pagar' },
                    { key: 'contasReceber', label: 'C. Receber' },
                    { key: 'fluxoCaixa', label: 'Fluxo Caixa' },
                    { key: 'centroCusto', label: 'Estrutura' },
                    { key: 'detalhes', label: 'Relatórios' },
                    { key: 'planCredencias', label: 'Usuários' }
                  ].map(perm => (
                    <td key={perm.key} className="p-5 border-b border-slate-100 text-center">
                      <label className="relative inline-flex items-center cursor-pointer group">
                        <input 
                          type="checkbox" 
                          className="sr-only peer"
                          checked={!!u.permissions[perm.key as keyof User['permissions']]} 
                          disabled={u.login === 'admin' && perm.key === 'planCredencias'}
                          onChange={() => togglePermission(u.login, perm.key as keyof User['permissions'])}
                        />
                        <div className="w-9 h-5 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-4 after:transition-all peer-checked:bg-blue-900"></div>
                      </label>
                    </td>
                  ))}

                  <td className="p-5 border-b border-slate-100 text-center">
                    {u.login !== 'admin' ? (
                      <button 
                        onClick={() => removeUser(u.login)}
                        className="w-9 h-9 flex items-center justify-center text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all mx-auto"
                        title="Remover Usuário"
                      >
                        <i className="fa-solid fa-trash-can"></i>
                      </button>
                    ) : (
                      <span className="text-[8px] font-black text-blue-900/20 uppercase tracking-widest">Master</span>
                    )}
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={9} className="p-20 text-center">
                    <div className="flex flex-col items-center gap-3 opacity-20">
                       <i className="fa-solid fa-users text-4xl"></i>
                       <p className="text-xs font-black uppercase tracking-[0.2em]">Nenhum usuário ativo</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default CredentialsManager;

import React, { useState } from 'react';
import { User } from '../types';

interface CredentialsManagerProps {
  users: User[];
  onUpdateUsers: (users: User[]) => void;
}

const CredentialsManager: React.FC<CredentialsManagerProps> = ({ users, onUpdateUsers }) => {
  const [newLogin, setNewLogin] = useState('');
  const [newSenha, setNewSenha] = useState('');
  const [newEmail, setNewEmail] = useState('');
  const [isAdding, setIsAdding] = useState(false);

  // Usuários que explicitamente solicitaram acesso (approved === false)
  const pendingUsers = users.filter(u => u.approved === false);

  // Usuários aprovados ou legados (sem o campo approved definido ainda)
  const activeUsers = users.filter(u => u.approved !== false);

  const handleAddUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newLogin || !newSenha || !newEmail) {
      alert('Por favor, preencha todos os campos obrigatórios.');
      return;
    }

    const newUser: User = {
      login: newLogin,
      senha: newSenha,
      email: newEmail,
      approved: true, 
      permissions: {
        centroCusto: false,
        contasPagar: false,
        contasReceber: false,
        dashboard: false,
        fluxoCaixa: false,
        detalhes: false,
        planCredencias: false
      }
    };

    onUpdateUsers([...users, newUser]);
    setNewLogin('');
    setNewSenha('');
    setNewEmail('');
    setIsAdding(false);
  };

  const handleApprove = (login: string) => {
    const updatedUsers = users.map(u => {
      if (u.login === login) {
        return { ...u, approved: true };
      }
      return u;
    });
    onUpdateUsers(updatedUsers);
  };

  const togglePermission = (login: string, permission: keyof User['permissions']) => {
    const updatedUsers = users.map(u => {
      if (u.login === login) {
        const currentPermissions = u.permissions || {
          centroCusto: false, contasPagar: false, contasReceber: false,
          dashboard: false, fluxoCaixa: false, detalhes: false, planCredencias: false
        };
        return {
          ...u,
          permissions: {
            ...currentPermissions,
            [permission]: !currentPermissions[permission]
          }
        };
      }
      return u;
    });
    onUpdateUsers(updatedUsers);
  };

  const removeUser = (login: string) => {
    if (login === 'admin') {
      alert('O usuário administrador master não pode ser removido.');
      return;
    }
    if (confirm(`Tem certeza que deseja remover o usuário "${login}"?`)) {
      onUpdateUsers(users.filter(u => u.login !== login));
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-700">

      {/* SEÇÃO 1: SOLICITAÇÕES PENDENTES */}
      {pendingUsers.length > 0 && (
        <div className="bg-white rounded-3xl border-2 border-orange-200 overflow-hidden shadow-xl shadow-orange-900/5">
          <div className="bg-orange-50 px-6 py-4 border-b border-orange-100 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-orange-500 text-white rounded-xl flex items-center justify-center shadow-lg animate-bounce">
                <i className="fa-solid fa-user-plus"></i>
              </div>
              <div>
                <h3 className="text-lg font-black text-orange-900 uppercase tracking-tighter">Solicitações Pendentes</h3>
                <p className="text-[10px] font-bold text-orange-600 uppercase tracking-widest">Aprove o acesso para novos colaboradores</p>
              </div>
            </div>
            <span className="bg-orange-500 text-white px-3 py-1 rounded-full text-[10px] font-black">{pendingUsers.length} PENDENTE(S)</span>
          </div>

          <div className="p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {pendingUsers.map(u => (
              <div key={u.login} className="bg-slate-50 p-5 rounded-2xl border border-slate-100 flex flex-col justify-between hover:border-orange-300 transition-all group">
                <div className="mb-4">
                  <div className="flex items-center gap-2 mb-1">
                    <span className="w-2 h-2 rounded-full bg-orange-500"></span>
                    <p className="text-sm font-black text-slate-800 uppercase tracking-tight">{u.login}</p>
                  </div>
                  <p className="text-[10px] text-slate-400 font-bold lowercase truncate px-4">{u.email}</p>
                </div>
                <div className="flex gap-2">
                  <button 
                    onClick={() => handleApprove(u.login)}
                    className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-lg shadow-emerald-600/20 active:scale-95"
                  >
                    Aprovar Acesso
                  </button>
                  <button 
                    onClick={() => removeUser(u.login)}
                    className="bg-white hover:bg-red-50 hover:text-red-600 text-slate-300 py-2.5 px-4 rounded-xl border border-slate-100 transition-all active:scale-95"
                  >
                    <i className="fa-solid fa-trash-can"></i>
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* SEÇÃO 2: USUÁRIOS ATIVOS E PERMISSÕES */}
      <div className="bg-white rounded-3xl shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
        <div className="p-8 flex flex-col sm:flex-row sm:items-center justify-between gap-6 border-b border-slate-50">
          <div>
            <h2 className="text-2xl font-black text-blue-900 uppercase tracking-tighter">Gestão de Usuários</h2>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Controle de telas e permissões por colaborador</p>
          </div>
          <button 
            onClick={() => setIsAdding(!isAdding)}
            className="bg-blue-900 hover:bg-blue-800 text-white px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-3 transition-all shadow-xl shadow-blue-900/30 active:scale-95"
          >
            <i className={`fa-solid ${isAdding ? 'fa-xmark' : 'fa-plus'}`}></i>
            {isAdding ? 'Cancelar Cadastro' : 'Cadastrar Manualmente'}
          </button>
        </div>

        {isAdding && (
          <form onSubmit={handleAddUser} className="bg-blue-50/50 p-8 border-b border-blue-100 grid grid-cols-1 md:grid-cols-4 gap-6 items-end animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-blue-900 uppercase tracking-widest">Login de Acesso</label>
              <input 
                type="text" 
                className="w-full p-4 text-xs font-bold border border-blue-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 transition-all bg-white" 
                placeholder="Ex: joao.admin"
                value={newLogin}
                onChange={(e) => setNewLogin(e.target.value)}
                required
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-blue-900 uppercase tracking-widest">E-mail</label>
              <input 
                type="email" 
                className="w-full p-4 text-xs font-bold border border-blue-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 transition-all bg-white" 
                placeholder="colaborador@multiplan.com"
                value={newEmail}
                onChange={(e) => setNewEmail(e.target.value)}
                required
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-blue-900 uppercase tracking-widest">Senha Inicial</label>
              <input 
                type="password" 
                className="w-full p-4 text-xs font-bold border border-blue-200 rounded-xl outline-none focus:ring-4 focus:ring-blue-900/5 transition-all bg-white" 
                placeholder="••••••"
                value={newSenha}
                onChange={(e) => setNewSenha(e.target.value)}
                required
              />
            </div>
            <button type="submit" className="bg-orange-500 text-white py-4.5 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-orange-600 transition-all shadow-lg shadow-orange-500/20 active:scale-95">
              Criar e Liberar
            </button>
          </form>
        )}

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-900 text-white text-[10px] uppercase font-black tracking-widest">
                <th className="p-6">Usuário</th>
                <th className="p-6 text-center">Dashboard</th>
                <th className="p-6 text-center">C. Pagar</th>
                <th className="p-6 text-center">C. Receber</th>
                <th className="p-6 text-center">F. Caixa</th>
                <th className="p-6 text-center">Estrutura</th>
                <th className="p-6 text-center">Relatórios</th>
                <th className="p-6 text-center">Usuários</th>
                <th className="p-6 text-center">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {activeUsers.length > 0 ? activeUsers.map((u, idx) => (
                <tr key={u.login} className={`group hover:bg-blue-50/30 transition-colors ${idx % 2 === 0 ? 'bg-white' : 'bg-slate-50/30'}`}>
                  <td className="p-6">
                    <div className="font-black text-blue-900 uppercase tracking-tight">{u.login}</div>
                    <div className="text-[10px] text-slate-400 font-bold lowercase mt-0.5">{u.email || 'N/A'}</div>
                  </td>

                  {[
                    { key: 'dashboard', label: 'Dashboard' },
                    { key: 'contasPagar', label: 'C. Pagar' },
                    { key: 'contasReceber', label: 'C. Receber' },
                    { key: 'fluxoCaixa', label: 'F. Caixa' },
                    { key: 'centroCusto', label: 'Estrutura' },
                    { key: 'detalhes', label: 'Relatórios' },
                    { key: 'planCredencias', label: 'Usuários' }
                  ].map(perm => (
                    <td key={perm.key} className="p-6 text-center">
                      <label className="relative inline-flex items-center cursor-pointer">
                        <input 
                          type="checkbox" 
                          className="sr-only peer"
                          checked={u.permissions ? !!u.permissions[perm.key as keyof User['permissions']] : false} 
                          disabled={u.login === 'admin' && perm.key === 'planCredencias'}
                          onChange={() => togglePermission(u.login, perm.key as keyof User['permissions'])}
                        />
                        <div className="w-10 h-5 bg-slate-200 rounded-full peer peer-checked:bg-emerald-500 after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:rounded-full after:h-4 after:w-4 after:transition-all peer-checked:after:translate-x-5 shadow-inner"></div>
                      </label>
                    </td>
                  ))}

                  <td className="p-6 text-center">
                    {u.login !== 'admin' ? (
                      <button 
                        onClick={() => removeUser(u.login)}
                        className="text-slate-300 hover:text-red-600 w-10 h-10 flex items-center justify-center rounded-xl hover:bg-red-50 transition-all mx-auto"
                        title="Remover"
                      >
                        <i className="fa-solid fa-trash-can"></i>
                      </button>
                    ) : (
                      <div className="text-[8px] font-black text-blue-900 bg-blue-100 px-2 py-1 rounded uppercase tracking-widest inline-block">Master</div>
                    )}
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={9} className="p-32 text-center">
                    <div className="flex flex-col items-center gap-4 opacity-20">
                      <i className="fa-solid fa-users-slash text-6xl"></i>
                      <p className="text-sm font-black uppercase tracking-widest">Nenhum usuário cadastrado</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default CredentialsManager;
